const SKELETON_SRC="// src/components/Skeleton.jsx\n// Blocs \"squelette\" fa\u00e7on Facebook (shimmer) \u2014 utilis\u00e9s pendant le chargement\n// des pages, \u00e0 la place d'un simple \"Chargement...\".\nexport function SkeletonBlock({ w = '100%', h = 14, r = 8, style = {} }) {\n  return (\n    <div className=\"skeleton-shimmer\" style={{ width: w, height: h, borderRadius: r, ...style }} />\n  );\n}\n\nexport function SkeletonCircle({ size = 40, style = {} }) {\n  return (\n    <div className=\"skeleton-shimmer\" style={{ width: size, height: size, borderRadius: '50%', flexShrink: 0, ...style }} />\n  );\n}\n\n// Squelette d'une publication du fil d'actualit\u00e9s (avatar + lignes + image)\nexport function SkeletonPost() {\n  return (\n    <div className=\"card\" style={{ marginBottom: 12, padding: 14 }}>\n      <div style={{ display: 'flex', alignItems: 'center', gap: 10, marginBottom: 12 }}>\n        <SkeletonCircle size={40} />\n        <div style={{ flex: 1 }}>\n          <SkeletonBlock w=\"45%\" h={13} style={{ marginBottom: 6 }} />\n          <SkeletonBlock w=\"25%\" h={10} />\n        </div>\n      </div>\n      <SkeletonBlock w=\"90%\" h={12} style={{ marginBottom: 6 }} />\n      <SkeletonBlock w=\"70%\" h={12} style={{ marginBottom: 12 }} />\n      <SkeletonBlock w=\"100%\" h={180} r={12} />\n    </div>\n  );\n}\n\n// Squelette d'une liste (Amis, Recherche, Enregistr\u00e9s, Admin...) : lignes\n// r\u00e9p\u00e9t\u00e9es avatar + texte, fa\u00e7on Facebook.\nexport function SkeletonList({ rows = 5, avatar = true }) {\n  return (\n    <div>\n      {Array.from({ length: rows }).map((_, i) => (\n        <div key={i} style={{ display: 'flex', alignItems: 'center', gap: 12, padding: '10px 4px' }}>\n          {avatar && <SkeletonCircle size={44} />}\n          <div style={{ flex: 1 }}>\n            <SkeletonBlock w={`${55 - (i % 3) * 8}%`} h={13} style={{ marginBottom: 7 }} />\n            <SkeletonBlock w={`${32 - (i % 3) * 5}%`} h={10} />\n          </div>\n        </div>\n      ))}\n    </div>\n  );\n}\n\n// Squelette d'une publication seule (page PostDetail)\nexport function SkeletonSinglePost() {\n  return (\n    <div style={{ padding: 14 }}>\n      <div style={{ display: 'flex', alignItems: 'center', gap: 10, marginBottom: 14 }}>\n        <SkeletonCircle size={44} />\n        <div style={{ flex: 1 }}>\n          <SkeletonBlock w=\"40%\" h={14} style={{ marginBottom: 6 }} />\n          <SkeletonBlock w=\"22%\" h={10} />\n        </div>\n      </div>\n      <SkeletonBlock w=\"95%\" h={13} style={{ marginBottom: 8 }} />\n      <SkeletonBlock w=\"75%\" h={13} style={{ marginBottom: 16 }} />\n      <SkeletonBlock w=\"100%\" h={320} r={14} style={{ marginBottom: 16 }} />\n      <div style={{ display: 'flex', gap: 10, marginBottom: 16 }}>\n        <SkeletonBlock w=\"33%\" h={36} r={18} />\n        <SkeletonBlock w=\"33%\" h={36} r={18} />\n        <SkeletonBlock w=\"33%\" h={36} r={18} />\n      </div>\n      {[0, 1].map((i) => (\n        <div key={i} style={{ display: 'flex', gap: 10, marginBottom: 14 }}>\n          <SkeletonCircle size={34} />\n          <div style={{ flex: 1 }}>\n            <SkeletonBlock w=\"60%\" h={12} style={{ marginBottom: 6 }} />\n            <SkeletonBlock w=\"40%\" h={12} />\n          </div>\n        </div>\n      ))}\n    </div>\n  );\n}\n\n// Squelette d'une page \"canal\" (Artiste / Boutique) : banni\u00e8re, titre,\n// boutons, carte info, galerie horizontale \u2014 correspond au visuel Facebook.\nexport function SkeletonChannelPage() {\n  return (\n    <div style={{ paddingBottom: 20 }}>\n      <div className=\"skeleton-shimmer\" style={{ height: 170, borderRadius: 0 }} />\n      <div style={{ padding: '16px 16px 0' }}>\n        <SkeletonBlock w=\"60%\" h={22} style={{ marginBottom: 8 }} />\n        <SkeletonBlock w=\"35%\" h={13} style={{ marginBottom: 16 }} />\n        <div style={{ display: 'flex', gap: 10, marginBottom: 20 }}>\n          <SkeletonBlock w=\"48%\" h={40} r={20} />\n          <SkeletonBlock w=\"48%\" h={40} r={20} />\n        </div>\n      </div>\n      <div style={{ height: 10, background: '#F0F2F5' }} />\n      <div style={{ padding: 16 }}>\n        <div style={{ background: '#F7F8FA', borderRadius: 14, padding: 16, marginBottom: 20 }}>\n          <SkeletonBlock w=\"70%\" h={14} style={{ marginBottom: 10 }} />\n          <SkeletonBlock w=\"95%\" h={12} style={{ marginBottom: 8 }} />\n          <SkeletonBlock w=\"80%\" h={12} style={{ marginBottom: 8 }} />\n          <SkeletonBlock w=\"55%\" h={12} />\n        </div>\n        <SkeletonBlock w=\"40%\" h={14} style={{ marginBottom: 12 }} />\n        <div style={{ display: 'flex', gap: 10 }}>\n          {[0, 1, 2].map((i) => (\n            <div key={i} style={{ flex: 1 }}>\n              <SkeletonBlock w=\"100%\" h={110} r={12} style={{ marginBottom: 6 }} />\n              <SkeletonBlock w=\"80%\" h={10} />\n            </div>\n          ))}\n        </div>\n      </div>\n      <div style={{ padding: '0 16px' }}>\n        <SkeletonPost />\n      </div>\n    </div>\n  );\n}\n";
const SEARCH_SRC="// src/pages/Search.jsx \u2014 Recherche plein \u00e9cran (format Facebook)\n// R\u00e9sultats par cat\u00e9gorie : Comptes \u00b7 Groupes \u00b7 Publications\nimport { useState, useEffect, useRef } from 'react';\nimport { useNavigate } from 'react-router-dom';\nimport { collection, getDocs, query, where, orderBy, limit } from 'firebase/firestore';\nimport { db } from '../firebase';\nimport { SkeletonList } from '../components/Skeleton';\nimport { useAuth } from '../context/AuthContext';\nimport { parseAppLink } from '../utils/appLink';\nimport { HiArrowLeft, HiSearch, HiUserGroup, HiX, HiChevronRight } from 'react-icons/hi';\n\nexport default function Search() {\n  const { currentUser } = useAuth();\n  const navigate = useNavigate();\n\n  const [term,   setTerm]   = useState('');\n  const [users,  setUsers]  = useState([]);\n  const [groups, setGroups] = useState([]);\n  const [posts,  setPosts]  = useState([]);\n  const [loaded, setLoaded] = useState(false);\n  const [submitted, setSubmitted] = useState('');   // Entr\u00e9e = page r\u00e9sultats\n  const [tab, setTab] = useState('tout');           // tout | comptes | groupes | publications\n  const inputRef = useRef();\n\n  // Charger les donn\u00e9es une fois (filtrage c\u00f4t\u00e9 client, comme la recherche existante)\n  useEffect(() => {\n    let alive = true;\n    Promise.all([\n      getDocs(collection(db, 'users')).catch(() => null),\n      getDocs(query(collection(db, 'groups'), where('type', '==', 'page'))).catch(() => null),\n      getDocs(query(collection(db, 'posts'), orderBy('createdAt', 'desc'), limit(200))).catch(() => null),\n    ]).then(([uSnap, gSnap, pSnap]) => {\n      if (!alive) return;\n      if (uSnap) setUsers(uSnap.docs.map(d => ({ uid: d.id, ...d.data() })).filter(u => u.fullName));\n      if (gSnap) setGroups(gSnap.docs.map(d => ({ id: d.id, ...d.data() })));\n      if (pSnap) setPosts(pSnap.docs.map(d => ({ id: d.id, ...d.data() })));\n      setLoaded(true);\n    });\n    inputRef.current?.focus();\n    return () => { alive = false; };\n  }, []);\n\n  const isResults = !!submitted;                    // mode \"page r\u00e9sultats\" (apr\u00e8s Entr\u00e9e)\n  const q = (isResults ? submitted : term).trim().toLowerCase();\n  const match = txt => (txt || '').toLowerCase().includes(q);\n\n  // Suggestions (manoratra) : vitsy. R\u00e9sultats (Entr\u00e9e) : feno.\n  const uAll = q ? users.filter(u => match(u.fullName) || match(u.username))\n                 : users.filter(u => u.uid !== currentUser?.uid);\n  const gAll = q ? groups.filter(g => match(g.name) || match(g.description)) : groups;\n  const pAll = q ? posts.filter(p => match(p.content) || match(p.authorName) || match(p.groupName)) : [];\n\n  const uRes = isResults ? uAll.slice(0, 25) : uAll.slice(0, q ? 8 : 5);\n  const gRes = isResults ? gAll.slice(0, 20) : gAll.slice(0, q ? 6 : 4);\n  const pRes = isResults ? pAll.slice(0, 40) : pAll.slice(0, 10);\n\n  function submitSearch() {\n    if (!term.trim()) return;\n    setSubmitted(term.trim());\n    setTab('tout');\n    inputRef.current?.blur();\n  }\n  function backFromResults() {\n    if (isResults) { setSubmitted(''); setTimeout(() => inputRef.current?.focus(), 50); }\n    else navigate(-1);\n  }\n\n  const av = (photo, name) => photo || `https://ui-avatars.com/api/?name=${encodeURIComponent(name || 'U')}&background=1877F2&color=fff`;\n\n  const SectionTitle = ({ children }) => (\n    <p style={{ padding: '14px 16px 8px', fontSize: 15, fontWeight: 800 }}>{children}</p>\n  );\n\n  return (\n    <div style={{ minHeight: '60vh' }}>\n      {/* Barre de recherche plein \u00e9cran (format Facebook) */}\n      <div style={{ display: 'flex', alignItems: 'center', gap: 8, padding: '10px 12px', borderBottom: '1px solid #E4E6EB', position: 'sticky', top: 0, background: 'white', zIndex: 20 }}>\n        <button onClick={backFromResults} style={{ background: 'none', border: 'none', cursor: 'pointer', color: '#050505', padding: 4 }}>\n          <HiArrowLeft size={22} />\n        </button>\n        <div style={{ position: 'relative', flex: 1 }}>\n          <HiSearch style={{ position: 'absolute', left: 13, top: '50%', transform: 'translateY(-50%)', color: '#65676B' }} />\n          <input ref={inputRef} className=\"input\" placeholder=\"Rechercher sur Trengo\" value={term}\n            onChange={e => { const l = parseAppLink(e.target.value); if (l) { setTerm(''); navigate(l); return; } setTerm(e.target.value); if (submitted) setSubmitted(''); }}\n            onKeyDown={e => { if (e.key === 'Enter') submitSearch(); }}\n            enterKeyHint=\"search\"\n            style={{ paddingLeft: 36, paddingRight: 34, borderRadius: 30, fontSize: 14 }} />\n          {term && (\n            <button onClick={() => { setTerm(''); inputRef.current?.focus(); }}\n              style={{ position: 'absolute', right: 8, top: '50%', transform: 'translateY(-50%)', background: '#E4E6EB', border: 'none', borderRadius: '50%', width: 22, height: 22, cursor: 'pointer', color: '#050505', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>\n              <HiX size={13} />\n            </button>\n          )}\n        </div>\n      </div>\n\n      {!loaded && <div style={{ padding: '10px 16px' }}><SkeletonList rows={6} /></div>}\n\n      {loaded && !q && (\n        <p style={{ padding: '12px 16px 0', fontSize: 13, color: '#65676B' }}>Suggestions</p>\n      )}\n\n      {/* \u2500\u2500 Page r\u00e9sultats (apr\u00e8s Entr\u00e9e) : onglets format Facebook \u2500\u2500 */}\n      {isResults && (\n        <>\n          <p style={{ padding: '12px 16px 0', fontSize: 14 }}>\n            R\u00e9sultats pour <span style={{ fontWeight: 800 }}>\u00ab {submitted} \u00bb</span>\n          </p>\n          <div style={{ display: 'flex', gap: 8, padding: '10px 12px', overflowX: 'auto', borderBottom: '1px solid #E4E6EB', scrollbarWidth: 'none' }}>\n            {[['tout', 'Tout'], ['comptes', `Comptes ${uAll.length ? `(${uAll.length})` : ''}`], ['groupes', `Groupes ${gAll.length ? `(${gAll.length})` : ''}`], ['publications', `Publications ${pAll.length ? `(${pAll.length})` : ''}`]].map(([k, label]) => (\n              <button key={k} onClick={() => setTab(k)}\n                style={{ flexShrink: 0, padding: '7px 16px', borderRadius: 20, border: 'none', cursor: 'pointer', fontFamily: 'Poppins', fontSize: 13, fontWeight: 700,\n                  background: tab === k ? '#1877F2' : '#F0F2F5', color: tab === k ? 'white' : '#050505' }}>\n                {label}\n              </button>\n            ))}\n          </div>\n        </>\n      )}\n\n      {/* \u2500\u2500 Comptes \u2500\u2500 */}\n      {(!isResults || tab === 'tout' || tab === 'comptes') && uRes.length > 0 && (\n        <>\n          <SectionTitle>Comptes</SectionTitle>\n          {uRes.map(u => (\n            <div key={u.uid} onClick={() => navigate(`/profile/${u.uid}`)}\n              style={{ display: 'flex', alignItems: 'center', gap: 12, padding: '9px 16px', cursor: 'pointer' }}>\n              <img src={av(u.photoURL, u.fullName)} alt=\"\" style={{ width: 44, height: 44, borderRadius: '50%', objectFit: 'cover' }} />\n              <div style={{ flex: 1, minWidth: 0 }}>\n                <p style={{ fontWeight: 700, fontSize: 14, overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>{u.fullName}</p>\n                <p style={{ fontSize: 12, color: '#65676B' }}>@{u.username}</p>\n              </div>\n              <HiChevronRight size={18} color=\"#65676B\" />\n            </div>\n          ))}\n        </>\n      )}\n\n      {/* \u2500\u2500 Groupes \u2500\u2500 */}\n      {(!isResults || tab === 'tout' || tab === 'groupes') && gRes.length > 0 && (\n        <>\n          <SectionTitle>Groupes</SectionTitle>\n          {gRes.map(g => (\n            <div key={g.id} onClick={() => navigate(`/groups/${g.id}`)}\n              style={{ display: 'flex', alignItems: 'center', gap: 12, padding: '9px 16px', cursor: 'pointer' }}>\n              <div style={{ width: 44, height: 44, borderRadius: 12, background: 'linear-gradient(135deg,#1B84FF,#1877F2)', display: 'flex', alignItems: 'center', justifyContent: 'center', overflow: 'hidden', flexShrink: 0 }}>\n                {g.photoURL ? <img src={g.photoURL} alt=\"\" style={{ width: '100%', height: '100%', objectFit: 'cover' }} /> : <HiUserGroup size={22} color=\"white\" />}\n              </div>\n              <div style={{ flex: 1, minWidth: 0 }}>\n                <p style={{ fontWeight: 700, fontSize: 14, overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>{g.name}</p>\n                <p style={{ fontSize: 12, color: '#65676B' }}>Groupe public \u00b7 {g.members?.length || 0} membre{(g.members?.length || 0) > 1 ? 's' : ''}</p>\n              </div>\n              <HiChevronRight size={18} color=\"#65676B\" />\n            </div>\n          ))}\n        </>\n      )}\n\n      {/* \u2500\u2500 Publications \u2500\u2500 */}\n      {(!isResults || tab === 'tout' || tab === 'publications') && pRes.length > 0 && (\n        <>\n          <SectionTitle>Publications</SectionTitle>\n          {pRes.map(p => (\n            <div key={p.id} onClick={() => navigate(`/post/${p.id}`)}\n              style={{ display: 'flex', alignItems: 'center', gap: 12, padding: '9px 16px', cursor: 'pointer' }}>\n              <img src={av(p.authorPhoto, p.authorName)} alt=\"\" style={{ width: 40, height: 40, borderRadius: '50%', objectFit: 'cover', flexShrink: 0 }} />\n              <div style={{ flex: 1, minWidth: 0 }}>\n                <p style={{ fontWeight: 700, fontSize: 13 }}>\n                  {p.authorName}{p.groupName ? <span style={{ color: '#65676B', fontWeight: 500 }}> \u00b7 dans {p.groupName}</span> : ''}\n                </p>\n                <p style={{ fontSize: 13, color: '#050505', overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>\n                  {p.content || (p.mediaType === 'video' ? '\ud83c\udfac Vid\u00e9o' : '\ud83d\udcf7 Photo')}\n                </p>\n              </div>\n              {p.mediaURL && p.mediaType === 'image' && (\n                <img src={p.mediaURL} alt=\"\" style={{ width: 46, height: 46, borderRadius: 8, objectFit: 'cover', flexShrink: 0 }} />\n              )}\n            </div>\n          ))}\n        </>\n      )}\n\n      {loaded && q && uRes.length === 0 && gRes.length === 0 && pRes.length === 0 && (\n        <p style={{ padding: 40, textAlign: 'center', color: '#65676B', fontSize: 14 }}>\n          Aucun r\u00e9sultat pour \u00ab {term} \u00bb\n        </p>\n      )}\n    </div>\n  );\n}\n";
const SAVED_SRC="// src/pages/Saved.jsx \u2014 Enregistrements (publications & vid\u00e9os sauvegard\u00e9es)\nimport { useState, useEffect } from 'react';\nimport { useNavigate } from 'react-router-dom';\nimport { doc, getDoc, updateDoc, arrayRemove } from 'firebase/firestore';\nimport { db } from '../firebase';\nimport { SkeletonList } from '../components/Skeleton';\nimport { useAuth } from '../context/AuthContext';\nimport { HiBookmark, HiTrash, HiChevronRight, HiUserGroup } from 'react-icons/hi';\n\nexport default function Saved() {\n  const { currentUser, userProfile, setUserProfile } = useAuth();\n  const navigate = useNavigate();\n  const [items, setItems] = useState([]);\n  const [loaded, setLoaded] = useState(false);\n\n  const savedIds = userProfile?.saved || [];\n\n  useEffect(() => {\n    let alive = true;\n    if (savedIds.length === 0) { setItems([]); setLoaded(true); return; }\n    Promise.all(savedIds.map(id =>\n      getDoc(doc(db, 'posts', id)).then(s => s.exists() ? { id: s.id, ...s.data() } : null).catch(() => null)\n    )).then(list => {\n      if (!alive) return;\n      setItems(list.filter(Boolean).reverse()); // les plus r\u00e9cents enregistr\u00e9s en premier\n      setLoaded(true);\n    });\n    return () => { alive = false; };\n  }, [savedIds.join(',')]);\n\n  async function removeSaved(postId) {\n    try {\n      await updateDoc(doc(db, 'users', currentUser.uid), { saved: arrayRemove(postId) });\n      setUserProfile(p => ({ ...p, saved: (p.saved || []).filter(id => id !== postId) }));\n    } catch (err) { alert('Erreur : ' + (err?.message || err)); }\n  }\n\n  return (\n    <div style={{ padding: '14px 12px' }}>\n      <h2 style={{ fontWeight: 800, fontSize: 20, display: 'flex', alignItems: 'center', gap: 8, marginBottom: 14 }}>\n        <HiBookmark size={24} color=\"#F2B300\" /> Enregistrements\n      </h2>\n\n      {!loaded && <SkeletonList rows={5} avatar={false} />}\n\n      {loaded && items.length === 0 && (\n        <div className=\"card\" style={{ padding: 30, textAlign: 'center' }}>\n          <HiBookmark size={40} color=\"#F2B300\" style={{ marginBottom: 8 }} />\n          <p style={{ fontWeight: 700, marginBottom: 4 }}>Aucun enregistrement</p>\n          <p style={{ fontSize: 13, color: '#65676B' }}>\n            Touchez \u22ee sur une publication ou une vid\u00e9o puis \u00ab Enregistrer \u00bb pour la retrouver ici.\n          </p>\n        </div>\n      )}\n\n      {items.map(p => (\n        <div key={p.id} className=\"card\" style={{ marginBottom: 10, overflow: 'hidden' }}>\n          <div style={{ display: 'flex', alignItems: 'center', gap: 12, padding: 12, cursor: 'pointer' }}\n            onClick={() => navigate(`/post/${p.id}`)}>\n            {/* Miniature */}\n            {p.mediaURL ? (\n              p.isMusic\n                ? <div style={{ width: 64, height: 64, borderRadius: 10, flexShrink: 0, overflow: 'hidden', position: 'relative', background: p.thumbURL ? `url(${p.thumbURL}) center/cover` : 'linear-gradient(145deg,#FF6FA5,#0c0c12)' }}>\n                    <div style={{ position: 'absolute', inset: 0, display: 'flex', alignItems: 'center', justifyContent: 'center', gap: 1.5, background: p.thumbURL ? 'rgba(0,0,0,.45)' : 'transparent' }}>\n                      {[9, 17, 12, 24, 15, 28, 13, 20, 10].map((h, i) => <div key={i} style={{ width: 2.5, height: h, borderRadius: 2, background: i < 5 ? '#FF6FA5' : '#FF2D8D' }} />)}\n                    </div>\n                  </div>\n                : p.mediaType === 'video'\n                  ? <video src={p.mediaURL} muted playsInline preload=\"metadata\" style={{ width: 64, height: 64, borderRadius: 10, objectFit: 'cover', flexShrink: 0, background: '#000' }} />\n                  : <img src={p.mediaURL} alt=\"\" style={{ width: 64, height: 64, borderRadius: 10, objectFit: 'cover', flexShrink: 0 }} />\n            ) : (\n              <div style={{ width: 64, height: 64, borderRadius: 10, background: '#E7F0FE', display: 'flex', alignItems: 'center', justifyContent: 'center', flexShrink: 0, fontSize: 24 }}>\ud83d\udcdd</div>\n            )}\n            <div style={{ flex: 1, minWidth: 0 }}>\n              <p style={{ fontWeight: 700, fontSize: 14 }}>\n                {p.authorName}\n                {p.groupName && <span style={{ color: '#65676B', fontWeight: 500 }}> \u00b7 <HiUserGroup size={11} style={{ verticalAlign: '-1px' }} /> {p.groupName}</span>}\n              </p>\n              <p style={{ fontSize: 13, color: '#050505', overflow: 'hidden', textOverflow: 'ellipsis', display: '-webkit-box', WebkitLineClamp: 2, WebkitBoxOrient: 'vertical' }}>\n                {p.isMusic ? (p.songTitle || 'Musique') : (p.content || (p.mediaType === 'video' ? '\ud83c\udfac Vid\u00e9o' : '\ud83d\udcf7 Photo'))}\n              </p>\n              <p style={{ fontSize: 11, color: '#65676B', marginTop: 2 }}>\n                {p.isMusic ? (p.mediaType === 'video' ? 'Clip enregistr\u00e9' : 'Musique enregistr\u00e9e') : p.mediaType === 'video' ? 'Vid\u00e9o enregistr\u00e9e' : 'Publication enregistr\u00e9e'}\n              </p>\n            </div>\n            <HiChevronRight size={18} color=\"#65676B\" style={{ flexShrink: 0 }} />\n          </div>\n          <button onClick={() => removeSaved(p.id)}\n            style={{ width: '100%', padding: '9px 0', background: '#F0F2F5', border: 'none', borderTop: '1px solid #E4E6EB', cursor: 'pointer', color: '#FF2D8D', fontSize: 12, fontWeight: 700, fontFamily: 'Poppins', display: 'flex', alignItems: 'center', justifyContent: 'center', gap: 6 }}>\n            <HiTrash size={14} /> Retirer des enregistrements\n          </button>\n        </div>\n      ))}\n    </div>\n  );\n}\n";
const FRIENDS_SRC="// src/pages/Friends.jsx\nimport { useState, useEffect } from 'react';\nimport { useNavigate } from 'react-router-dom';\nimport {\n  collection, query, where, getDocs, doc, getDoc,\n  updateDoc, arrayUnion, arrayRemove, addDoc, serverTimestamp,\n  onSnapshot, deleteDoc, orderBy\n} from 'firebase/firestore';\nimport { db } from '../firebase';\nimport { SkeletonList } from '../components/Skeleton';\nimport { useAuth } from '../context/AuthContext';\nimport { useLang } from '../context/LanguageContext';\nimport { getChatId } from '../utils/chat';\nimport { sendPushNotification } from '../utils/onesignal';\nimport { HiSearch, HiUserAdd, HiUserRemove, HiPaperAirplane, HiCheck, HiX, HiUsers } from 'react-icons/hi';\n\nfunction VIPBadge() {\n  return <img src='/vip-badge.png' style={{ width:32, height:32, marginLeft:5, verticalAlign:'middle', display:'inline-block', flexShrink:0, objectFit:'contain' }} alt='VIP'/>;\n}\n\nexport default function Friends() {\n  const { currentUser, userProfile, setUserProfile } = useAuth();\n  const { t } = useLang();\n  const navigate = useNavigate();\n\n  const [search, setSearch] = useState('');\n  const [searchResults, setSearchResults] = useState([]);\n  const [friends, setFriends] = useState([]);\n  const [requests, setRequests] = useState([]);\n  const [activeTab, setActiveTab] = useState('friends');\n  const [loading, setLoading] = useState(false);\n  const [actionLoading, setActionLoading] = useState({});\n  const [suggestions, setSuggestions] = useState([]);\n  const [suggLoading, setSuggLoading] = useState(false);\n  const [sentRequestUsers, setSentRequestUsers] = useState([]);\n\n  useEffect(() => {\n    if (!userProfile?.friends?.length) { setFriends([]); return; }\n    Promise.all(\n      userProfile.friends.map(uid =>\n        getDoc(doc(db, 'users', uid)).then(s => s.exists() ? { uid: s.id, ...s.data() } : null)\n      )\n    ).then(list => setFriends(list.filter(Boolean)));\n  }, [userProfile?.friends?.join?.(',')]);\n\n  useEffect(() => {\n    if (!userProfile?.sentRequests?.length) { setSentRequestUsers([]); return; }\n    Promise.all(\n      userProfile.sentRequests.map(uid =>\n        getDoc(doc(db, 'users', uid)).then(s => s.exists() ? { uid: s.id, ...s.data() } : null)\n      )\n    ).then(list => setSentRequestUsers(list.filter(Boolean)));\n  }, [userProfile?.sentRequests?.join?.(',')]);\n\n  useEffect(() => {\n    if (!currentUser) return;\n    const q = query(collection(db, 'friendRequests'), where('toUid', '==', currentUser.uid), where('status', '==', 'pending'));\n    const unsub = onSnapshot(q, async snap => {\n      const reqs = [];\n      for (const d of snap.docs) {\n        const data = d.data();\n        const userSnap = await getDoc(doc(db, 'users', data.fromUid));\n        if (userSnap.exists()) reqs.push({ reqId: d.id, ...data, user: userSnap.data() });\n      }\n      setRequests(reqs);\n    });\n    return unsub;\n  }, [currentUser]);\n\n  // Fetch suggestions (utilisateurs non amis, non d\u00e9j\u00e0 demand\u00e9s)\n  useEffect(() => {\n    if (!currentUser) return;\n    setSuggLoading(true);\n    getDocs(query(collection(db, 'users'), orderBy('fullName')))\n      .then(snap => {\n        const myFriends = userProfile?.friends || [];\n        const sentReqs  = userProfile?.sentRequests || [];\n        const list = snap.docs\n          .map(d => ({ uid: d.id, ...d.data() }))\n          .filter(u =>\n            u.uid !== currentUser.uid &&\n            !myFriends.includes(u.uid) &&\n            !sentReqs.includes(u.uid)\n          );\n        setSuggestions(list);\n      })\n      .catch(() => {})\n      .finally(() => setSuggLoading(false));\n  }, [currentUser, userProfile?.friends?.join?.(','), userProfile?.sentRequests?.join?.(',')]);\n\n  async function handleSearch(val) {\n    setSearch(val);\n    if (!val.trim() || val.length < 2) { setSearchResults([]); return; }\n    setLoading(true);\n    try {\n      const byUsername = query(collection(db, 'users'), where('username', '>=', val.toLowerCase()), where('username', '<=', val.toLowerCase() + '\\uf8ff'));\n      const byName = query(collection(db, 'users'), where('fullName', '>=', val), where('fullName', '<=', val + '\\uf8ff'));\n      const [s1, s2] = await Promise.all([getDocs(byUsername), getDocs(byName)]);\n      const seen = new Set();\n      const results = [];\n      [...s1.docs, ...s2.docs].forEach(d => {\n        if (d.id === currentUser.uid || seen.has(d.id)) return;\n        seen.add(d.id); results.push({ uid: d.id, ...d.data() });\n      });\n      setSearchResults(results);\n    } catch (err) { console.error(err); }\n    setLoading(false);\n  }\n\n  async function cancelRequest(toUid) {\n    try {\n      await updateDoc(doc(db, 'users', currentUser.uid), { sentRequests: arrayRemove(toUid) });\n      setUserProfile(p => ({ ...p, sentRequests: (p.sentRequests||[]).filter(id => id !== toUid) }));\n    } catch(e) { console.warn('cancelRequest:', e); }\n  }\n\n  async function sendRequest(toUser) {\n    if (!toUser?.uid) return;\n    setActionLoading(p => ({ ...p, [toUser.uid]: true }));\n    try {\n      const existing = query(collection(db, 'friendRequests'), where('fromUid', '==', currentUser.uid), where('toUid', '==', toUser.uid));\n      const snap = await getDocs(existing);\n      if (!snap.empty) return;\n      await addDoc(collection(db, 'friendRequests'), {\n        fromUid: currentUser.uid, toUid: toUser.uid,\n        fromName: userProfile.fullName, fromPhoto: userProfile.photoURL || '',\n        status: 'pending', createdAt: serverTimestamp(),\n      });\n      await addDoc(collection(db, 'notifications'), {\n        toUid: toUser.uid, fromUid: currentUser.uid,\n        fromName: userProfile.fullName, fromPhoto: userProfile.photoURL || '',\n        type: 'friendRequest',\n        message: `${userProfile.fullName} ${t('addFriend').toLowerCase()}`,\n        read: false, createdAt: serverTimestamp(),\n      });\n      // \u2705 FIX BUG #1: Push notification\n      sendPushNotification({\n        toExternalId: toUser.uid,\n        title: userProfile.fullName,\n        message: 'vous a envoy\u00e9 une demande d\\'ami \ud83d\udc65',\n        data: { type: 'friendRequest', fromUid: currentUser.uid },\n      });\n      await updateDoc(doc(db, 'users', currentUser.uid), { sentRequests: arrayUnion(toUser.uid) });\n      setUserProfile(p => ({ ...p, sentRequests: [...(p.sentRequests || []), toUser.uid] }));\n    } catch (err) { console.error(err); }\n    setActionLoading(p => ({ ...p, [toUser.uid]: false }));\n  }\n\n  async function acceptRequest(req) {\n    setActionLoading(p => ({ ...p, [req.reqId]: true }));\n    try {\n      await updateDoc(doc(db, 'users', currentUser.uid), { friends: arrayUnion(req.fromUid) });\n      await updateDoc(doc(db, 'users', req.fromUid), { friends: arrayUnion(currentUser.uid) });\n      await deleteDoc(doc(db, 'friendRequests', req.reqId));\n      await addDoc(collection(db, 'notifications'), {\n        toUid: req.fromUid, fromUid: currentUser.uid,\n        fromName: userProfile.fullName, fromPhoto: userProfile.photoURL || '',\n        type: 'friendAccepted',\n        message: `${userProfile.fullName} a accept\u00e9 votre demande d'ami`,\n        read: false, createdAt: serverTimestamp(),\n      });\n      // \u2705 FIX BUG #1: Push notification\n      sendPushNotification({\n        toExternalId: req.fromUid,\n        title: userProfile.fullName,\n        message: 'a accept\u00e9 votre demande d\\'ami \ud83c\udf89',\n        data: { type: 'friendAccepted', fromUid: currentUser.uid },\n      });\n      setUserProfile(p => ({ ...p, friends: [...(p.friends || []), req.fromUid] }));\n    } catch (err) { console.error(err); }\n    setActionLoading(p => ({ ...p, [req.reqId]: false }));\n  }\n\n  async function declineRequest(req) {\n    await deleteDoc(doc(db, 'friendRequests', req.reqId));\n  }\n\n  async function removeFriend(friendUid) {\n    if (!window.confirm('Esory ny namana?')) return;\n    await updateDoc(doc(db, 'users', currentUser.uid), { friends: arrayRemove(friendUid) });\n    await updateDoc(doc(db, 'users', friendUid), { friends: arrayRemove(currentUser.uid) });\n    setUserProfile(p => ({ ...p, friends: (p.friends || []).filter(u => u !== friendUid) }));\n    setFriends(p => p.filter(f => f.uid !== friendUid));\n  }\n\n  async function blockFriend(friendUid) {\n    if (!window.confirm(\"Bloquer cet ami ?\")) return;\n    await updateDoc(doc(db, \"users\", currentUser.uid), { friends: arrayRemove(friendUid), blocked: arrayUnion(friendUid) });\n    await updateDoc(doc(db, \"users\", friendUid), { friends: arrayRemove(currentUser.uid) });\n    setUserProfile(p => ({ ...p, friends: (p.friends || []).filter(u => u !== friendUid), blocked: [...(p.blocked || []), friendUid] }));\n    setFriends(p => p.filter(f => f.uid !== friendUid));\n  }\n\n  function getRelation(uid) {\n    if ((userProfile?.friends || []).includes(uid)) return 'friend';\n    if ((userProfile?.sentRequests || []).includes(uid)) return 'sent';\n    return 'none';\n  }\n\n  const tabs = [\n    { key: 'friends',      label: t('myFriends'),        count: friends.length },\n    { key: 'requests',     label: t('pendingRequests'),  count: requests.length },\n    { key: 'sentRequests', label: 'Demandes envoy\u00e9es',   count: sentRequestUsers.length },\n    { key: 'suggestions',  label: 'Suggestions',         count: suggestions.length },\n  ];\n\n  return (\n    <div style={{ padding: '16px 12px' }}>\n      <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginBottom: 14 }}>\n        <h2 style={{ fontWeight: 700, fontSize: 20, color: '#1877F2' }}>{t('friends')}</h2>\n        <button onClick={() => setActiveTab(activeTab === 'search' ? 'friends' : 'search')} aria-label=\"Rechercher\"\n          style={{ width: 38, height: 38, borderRadius: '50%', border: 'none', cursor: 'pointer', display: 'flex', alignItems: 'center', justifyContent: 'center', background: activeTab === 'search' ? '#1877F2' : '#E4E6EB', color: activeTab === 'search' ? 'white' : '#1877F2', flexShrink: 0 }}>\n          <HiSearch size={18} />\n        </button>\n      </div>\n\n      {/* Tabs */}\n      <div style={{ display: 'flex', gap: 6, marginBottom: 16, overflowX: 'auto', paddingBottom: 4 }}>\n        {tabs.map(tab => (\n          <button\n            key={tab.key}\n            onClick={() => setActiveTab(tab.key)}\n            style={{\n              padding: '8px 16px', borderRadius: 20, border: 'none', cursor: 'pointer',\n              fontFamily: 'Poppins', fontWeight: 600, fontSize: 13, whiteSpace: 'nowrap',\n              background: activeTab === tab.key ? '#1877F2' : '#E4E6EB',\n              color: activeTab === tab.key ? 'white' : '#1877F2',\n            }}\n          >\n            {tab.label} {tab.count > 0 && `(${tab.count})`}\n          </button>\n        ))}\n      </div>\n\n      {/* Search */}\n      {activeTab === 'search' && (\n        <div>\n          <div style={{ position: 'relative', marginBottom: 14 }}>\n            <HiSearch style={{ position: 'absolute', left: 12, top: '50%', transform: 'translateY(-50%)', color: '#65676B' }} size={18} />\n            <input className=\"input\" placeholder={t('search')} value={search} onChange={e => handleSearch(e.target.value)} style={{ paddingLeft: 38 }} />\n          </div>\n          {loading && <p style={{ textAlign: 'center', color: '#65676B' }}>{t('loading')}</p>}\n          {searchResults.map(user => {\n            const rel = getRelation(user.uid);\n            return (\n              <div key={user.uid} className=\"card\" style={{ padding: '12px 14px', marginBottom: 10, display: 'flex', alignItems: 'center', gap: 12 }}>\n                <img\n                  src={user.photoURL || `https://ui-avatars.com/api/?name=${encodeURIComponent(user.fullName)}&background=1877F2&color=fff`}\n                  alt=\"\"\n                  onClick={() => navigate(`/profile/${user.uid}`)}\n                  style={{ cursor: 'pointer', width: 50, height: 50, borderRadius: '50%', objectFit: 'cover', flexShrink: 0 }}\n                />\n                <div style={{ flex: 1 }}>\n                  <p style={{ fontWeight: 600, fontSize: 15 }}>{user.fullName}{user.isVip && <VIPBadge />}</p>\n                  <p style={{ fontSize: 13, color: '#65676B' }}>@{user.username}</p>\n                  <p style={{ fontSize: 12, color: '#65676B' }}>{user.friends?.length || 0} {t('myFriends').toLowerCase()}</p>\n                </div>\n                <div style={{ display: 'flex', flexDirection: 'column', gap: 6 }}>\n                  {rel === 'friend' ? (\n                    <>\n                      <button\n                        onClick={() => navigate(`/messages/${getChatId(currentUser.uid, user.uid)}`)}\n                        style={{ background: '#E4E6EB', border: 'none', borderRadius: 20, padding: '6px 12px', cursor: 'pointer', color: '#1877F2', fontWeight: 600, fontSize: 12, display: 'flex', alignItems: 'center', gap: 4 }}\n                      >\n                        <HiPaperAirplane size={14} /> {t('message')}\n                      </button>\n                      <button onClick={() => removeFriend(user.uid)} style={{ background: 'none', border: '1px solid #E4E6EB', borderRadius: 20, padding: '5px 12px', cursor: 'pointer', color: '#65676B', fontSize: 12 }}>\n                        {t('removeFriend')}\n                      </button>\n                      <button onClick={() => blockFriend(user.uid)} style={{ background: \"none\", border: \"1px solid #1877F2\", borderRadius: 20, padding: \"5px 12px\", cursor: \"pointer\", color: \"#1877F2\", fontSize: 12 }}>\n                        \ud83d\udeab Bloquer\n                      </button>\n                    </>\n                  ) : rel === 'sent' ? (\n                    <span style={{ color: '#65676B', fontSize: 13, fontStyle: 'italic' }}>Voaravina...</span>\n                  ) : (\n                    <button\n                      onClick={() => sendRequest(user)}\n                      disabled={actionLoading[user.uid]}\n                      className=\"btn-primary\"\n                      style={{ fontSize: 12, padding: '6px 12px', display: 'flex', alignItems: 'center', gap: 4 }}\n                    >\n                      <HiUserAdd size={14} /> {t('addFriend')}\n                    </button>\n                  )}\n                </div>\n              </div>\n            );\n          })}\n        </div>\n      )}\n\n      {/* Demandes envoy\u00e9es */}\n      {activeTab === 'sentRequests' && (\n        <div>\n          {sentRequestUsers.length === 0 ? (\n            <div style={{ textAlign: 'center', padding: 40, color: '#65676B' }}>Aucune demande envoy\u00e9e</div>\n          ) : sentRequestUsers.map(user => (\n            <div key={user.uid} className=\"card\" style={{ padding: '12px 14px', marginBottom: 10, display: 'flex', alignItems: 'center', gap: 12 }}>\n              <img\n                src={user.photoURL || `https://ui-avatars.com/api/?name=${encodeURIComponent(user.fullName)}&background=1877F2&color=fff`}\n                alt=\"\"\n                onClick={() => navigate(`/profile/${user.uid}`)}\n                style={{ cursor: 'pointer', width: 50, height: 50, borderRadius: '50%', objectFit: 'cover', flexShrink: 0 }}\n              />\n              <div style={{ flex: 1, minWidth: 0 }}>\n                <p style={{ fontWeight: 600, fontSize: 15 }}>{user.fullName}{user.isVip && <VIPBadge />}</p>\n                <p style={{ fontSize: 13, color: '#65676B' }}>@{user.username}</p>\n              </div>\n              <button onClick={() => cancelRequest(user.uid)} style={{ background: 'none', border: '1px solid #E4E6EB', borderRadius: 20, padding: '6px 14px', cursor: 'pointer', color: '#65676B', fontSize: 12, fontWeight: 600, flexShrink: 0 }}>\n                Annuler\n              </button>\n            </div>\n          ))}\n        </div>\n      )}\n\n      {/* Friends list */}\n      {activeTab === 'friends' && (\n        <div>\n          {friends.length === 0 ? (\n            <div style={{ textAlign: 'center', padding: 40 }}>\n              <HiUsers size={48} color=\"#E4E6EB\" style={{ margin: '0 auto 12px', display: 'block' }} />\n              <p style={{ color: '#65676B' }}>{t('noFriends')}</p>\n              <button onClick={() => setActiveTab('search')} className=\"btn-primary\" style={{ marginTop: 14, fontSize: 13 }}>{t('search')}</button>\n            </div>\n          ) : (\n            friends.map(friend => (\n              <div key={friend.uid} className=\"card\" style={{ padding: '12px 14px', marginBottom: 10, display: 'flex', alignItems: 'center', gap: 12 }}>\n                <img\n                  src={friend.photoURL || `https://ui-avatars.com/api/?name=${encodeURIComponent(friend.fullName)}&background=1877F2&color=fff`}\n                  alt=\"\"\n                  style={{ width: 50, height: 50, borderRadius: '50%', objectFit: 'cover', cursor: 'pointer', flexShrink: 0 }}\n                  onClick={() => navigate(`/profile/${friend.uid}`)}\n                />\n                <div style={{ flex: 1 }}>\n                  <p style={{ fontWeight: 600, fontSize: 15 }}>{friend.fullName}{friend.isVip && <VIPBadge />}</p>\n                  <p style={{ fontSize: 13, color: '#65676B' }}>@{friend.username}</p>\n                </div>\n                <div style={{ display: 'flex', gap: 6 }}>\n                  <button\n                    onClick={() => navigate(`/messages/${getChatId(currentUser.uid, friend.uid)}`)}\n                    style={{ background: 'linear-gradient(135deg,#FF2D8D,#FF7AB8)', border: 'none', borderRadius: '50%', width: 36, height: 36, cursor: 'pointer', color: 'white', display: 'flex', alignItems: 'center', justifyContent: 'center' }}\n                  >\n                    <HiPaperAirplane size={17} />\n                  </button>\n                  <button\n                    onClick={() => navigate(`/profile/${friend.uid}`)}\n                    style={{ background: '#E4E6EB', border: 'none', borderRadius: '50%', width: 36, height: 36, cursor: 'pointer', color: '#1877F2', display: 'flex', alignItems: 'center', justifyContent: 'center' }}\n                  >\n                    <HiUserAdd size={17} />\n                  </button>\n                </div>\n              </div>\n            ))\n          )}\n        </div>\n      )}\n\n      {/* Requests */}\n      {activeTab === 'suggestions' && (\n        <div>\n          {suggLoading ? (\n            <SkeletonList rows={4} />\n          ) : suggestions.length === 0 ? (\n            <div style={{ textAlign:'center', padding:'40px 20px' }}>\n              <p style={{ fontSize:40, marginBottom:8 }}>\ud83c\udf89</p>\n              <p style={{ fontWeight:700, fontSize:17, marginBottom:6 }}>Vous connaissez tout le monde !</p>\n              <p style={{ color:'#65676B', fontSize:14 }}>Aucune suggestion pour l'instant.</p>\n            </div>\n          ) : (\n            <div style={{ display:'grid', gridTemplateColumns:'1fr 1fr', gap:10, padding:'4px 0' }}>\n              {suggestions.map(u => (\n                <div key={u.uid} style={{ border:'1px solid #E4E6EB', borderRadius:14, overflow:'hidden', background:'white' }}>\n                  <img\n                    src={u.photoURL || `https://ui-avatars.com/api/?name=${encodeURIComponent(u.fullName||'U')}&background=1877F2&color=fff`}\n                    alt=\"\"\n                    onClick={() => navigate(`/profile/${u.uid}`)}\n                    style={{ width:'100%', height:110, objectFit:'cover', cursor:'pointer', display:'block' }}\n                  />\n                  <div style={{ padding:'8px 8px 10px' }}>\n                    <p\n                      onClick={() => navigate(`/profile/${u.uid}`)}\n                      style={{ fontWeight:700, fontSize:13, overflow:'hidden', textOverflow:'ellipsis', whiteSpace:'nowrap', cursor:'pointer', marginBottom:2 }}\n                    >{u.fullName}</p>\n                    {u.username && <p style={{ fontSize:11, color:'#65676B', marginBottom:6 }}>@{u.username}</p>}\n                    {(userProfile?.sentRequests||[]).includes(u.uid) ? (\n                      <button\n                        onClick={() => cancelRequest(u.uid)}\n                        style={{ width:'100%', padding:'7px 0', fontSize:12, borderRadius:8, background:'#E4E6EB', color:'#65676B', border:'none', fontWeight:600, cursor:'pointer', fontFamily:'Poppins' }}\n                      >Annul\u00e9</button>\n                    ) : (userProfile?.friends||[]).includes(u.uid) ? (\n                      <button disabled style={{ width:'100%', padding:'7px 0', fontSize:12, borderRadius:8, background:'#E4E6EB', color:'#65676B', border:'none', fontWeight:600 }}>Ami \u2713</button>\n                    ) : (\n                      <button\n                        onClick={() => sendRequest(u)}\n                        disabled={actionLoading[u.uid]}\n                        style={{ width:'100%', padding:'7px 0', fontSize:12, borderRadius:8, background:'#1877F2', color:'white', border:'none', fontWeight:600, cursor:'pointer', fontFamily:'Poppins', display:'flex', alignItems:'center', justifyContent:'center', gap:5 }}\n                      >\n                        <HiUserAdd size={13}/> {actionLoading[u.uid] ? '...' : 'Ajouter'}\n                      </button>\n                    )}\n                  </div>\n                </div>\n              ))}\n            </div>\n          )}\n        </div>\n      )}\n\n      {activeTab === 'requests' && (\n        <div>\n          {requests.length === 0 ? (\n            <div style={{ textAlign: 'center', padding: 40, color: '#65676B' }}>Tsy misy fangatahana</div>\n          ) : (\n            requests.map(req => (\n              <div key={req.reqId} className=\"card\" style={{ padding: '12px 14px', marginBottom: 10, display: 'flex', alignItems: 'center', gap: 12 }}>\n                <img\n                  src={req.user.photoURL || `https://ui-avatars.com/api/?name=${encodeURIComponent(req.user.fullName)}&background=1877F2&color=fff`}\n                  alt=\"\"\n                  style={{ width: 50, height: 50, borderRadius: '50%', objectFit: 'cover', cursor: 'pointer', flexShrink: 0 }}\n                  onClick={() => navigate(`/profile/${req.fromUid}`)}\n                />\n                <div style={{ flex: 1 }}>\n                  <p style={{ fontWeight: 600, fontSize: 15 }}>{req.user.fullName}{req.user.isVip && <VIPBadge />}</p>\n                  <p style={{ fontSize: 13, color: '#65676B' }}>@{req.user.username}</p>\n                </div>\n                <div style={{ display: 'flex', gap: 8 }}>\n                  <button\n                    onClick={() => acceptRequest(req)}\n                    disabled={actionLoading[req.reqId]}\n                    style={{ background: '#1877F2', border: 'none', borderRadius: '50%', width: 36, height: 36, cursor: 'pointer', color: 'white', display: 'flex', alignItems: 'center', justifyContent: 'center' }}\n                  >\n                    <HiCheck size={18} />\n                  </button>\n                  <button\n                    onClick={() => declineRequest(req)}\n                    style={{ background: '#E4E6EB', border: 'none', borderRadius: '50%', width: 36, height: 36, cursor: 'pointer', color: '#1877F2', display: 'flex', alignItems: 'center', justifyContent: 'center' }}\n                  >\n                    <HiX size={18} />\n                  </button>\n                </div>\n              </div>\n            ))\n          )}\n        </div>\n      )}\n    </div>\n  );\n}\n";
const ADMIN_SRC="// src/pages/AdminPanel.jsx\n// Panel Admin complet : Utilisateurs (ID, VIP, blocage, d\u00e9sactivation),\n// Boost, Boutiques, Artistes, installation PWA + statistiques d\u00e9taill\u00e9es.\nimport { useState, useEffect } from 'react';\nimport {\n  collection, query, getDocs, doc, updateDoc, deleteDoc,\n  orderBy, getDoc, addDoc, serverTimestamp\n} from 'firebase/firestore';\nimport { db } from '../firebase';\nimport { useAuth } from '../context/AuthContext';\nimport { useNavigate } from 'react-router-dom';\nimport {\n  HiShieldCheck, HiStar, HiSearch, HiLightningBolt, HiX, HiClock,\n  HiChevronDown, HiChevronUp, HiBan, HiCheckCircle, HiTrash,\n  HiDownload, HiDuplicate, HiShoppingBag, HiMusicNote, HiUserGroup, HiMenu,\n  HiUsers, HiSpeakerphone\n} from 'react-icons/hi';\nimport { isStandalone, canInstall, onInstallChange, promptInstall } from '../utils/pwaInstall';\nimport PushDiagnostic from '../components/PushDiagnostic';\nimport { SkeletonList } from '../components/Skeleton';\n\nexport default function AdminPanel() {\n  const { currentUser, userProfile } = useAuth();\n  const navigate = useNavigate();\n\n  const [isAdmin, setIsAdmin] = useState(null);\n  const [activeTab, setActiveTab] = useState('users');\n\n  const [users, setUsers] = useState([]);\n  const [search, setSearch] = useState('');\n  const [loading, setLoading] = useState(false);\n  const [message, setMessage] = useState('');\n\n  const [posts, setPosts] = useState([]);\n  const [boostSearch, setBoostSearch] = useState('');\n  const [boostDays, setBoostDays] = useState({});\n  const [boostLoading, setBoostLoading] = useState({});\n  const [expandedPost, setExpandedPost] = useState(null);\n\n  const [shops, setShops] = useState([]);\n  const [artists, setArtists] = useState([]);\n  const [bizSearch, setBizSearch] = useState('');\n  const [navMenuOpen, setNavMenuOpen] = useState(false);\n  const [reports, setReports] = useState([]);\n  const [boostOrders, setBoostOrders] = useState([]);\n  const [ordersLoading, setOrdersLoading] = useState(false);\n\n  // \u2500\u2500 Installation PWA \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n  const [installState, setInstallState] = useState('unavailable'); // installed | ready | unavailable\n  useEffect(() => {\n    setInstallState(isStandalone() ? 'installed' : (canInstall() ? 'ready' : 'unavailable'));\n    return onInstallChange((available) => {\n      setInstallState(isStandalone() ? 'installed' : (available ? 'ready' : 'unavailable'));\n    });\n  }, []);\n  async function doInstall() {\n    const r = await promptInstall();\n    if (r.outcome === 'accepted') { setInstallState('installed'); showMsg('\u2705 Application install\u00e9e !'); }\n    else if (r.outcome === 'unavailable') showMsg(\"\u274c Installation indisponible (ouvrez dans Chrome, hors mode install\u00e9)\");\n    else showMsg('Installation annul\u00e9e');\n  }\n\n  // \u2500\u2500 V\u00e9rif admin \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n  useEffect(() => {\n    async function checkAdmin() {\n      if (!currentUser) { setIsAdmin(false); return; }\n      try {\n        const snap = await getDoc(doc(db, 'users', currentUser.uid));\n        if (snap.exists() && snap.data().isAdmin === true) {\n          setIsAdmin(true);\n          loadUsers(); loadPosts(); loadShops(); loadArtists(); loadBoostOrders(); loadReports();\n        } else setIsAdmin(false);\n      } catch { setIsAdmin(false); }\n    }\n    checkAdmin();\n  }, [currentUser]);\n\n  async function loadUsers() {\n    setLoading(true);\n    const snap = await getDocs(query(collection(db, 'users'), orderBy('fullName')));\n    setUsers(snap.docs.map(d => ({ id: d.id, ...d.data() })));\n    setLoading(false);\n  }\n  async function loadPosts() {\n    const snap = await getDocs(query(collection(db, 'posts'), orderBy('createdAt', 'desc')));\n    setPosts(snap.docs.map(d => ({ id: d.id, ...d.data() })));\n  }\n  async function loadShops() {\n    try {\n      const snap = await getDocs(query(collection(db, 'shops'), orderBy('createdAt', 'desc')));\n      setShops(snap.docs.map(d => ({ id: d.id, ...d.data() })));\n    } catch { setShops([]); }\n  }\n  async function loadArtists() {\n    try {\n      const snap = await getDocs(collection(db, 'artists'));\n      setArtists(snap.docs.map(d => ({ id: d.id, ...d.data() })));\n    } catch { setArtists([]); }\n  }\n\n  async function loadReports() {\n    try {\n      const snap = await getDocs(query(collection(db, 'reports'), orderBy('createdAt', 'desc')));\n      setReports(snap.docs.map(d => ({ id: d.id, ...d.data() })));\n    } catch (e) { setReports([]); }\n  }\n  async function resolveReport(r) {\n    try {\n      await updateDoc(doc(db, 'reports', r.id), { status: 'resolved', processedAt: new Date().toISOString() });\n      setReports(prev => prev.map(x => x.id === r.id ? { ...x, status: 'resolved' } : x));\n      showMsg('\u2705 Signalement trait\u00e9');\n    } catch (e) { showMsg('\u274c Erreur : ' + (e?.message || e)); }\n  }\n  async function dismissReport(r) {\n    try {\n      await updateDoc(doc(db, 'reports', r.id), { status: 'dismissed', processedAt: new Date().toISOString() });\n      setReports(prev => prev.map(x => x.id === r.id ? { ...x, status: 'dismissed' } : x));\n      showMsg('Signalement ignor\u00e9');\n    } catch (e) { showMsg('\u274c Erreur : ' + (e?.message || e)); }\n  }\n\n  async function loadBoostOrders() {\n    setOrdersLoading(true);\n    try {\n      const snap = await getDocs(query(collection(db, 'boostOrders'), orderBy('createdAt', 'desc')));\n      setBoostOrders(snap.docs.map(d => ({ id: d.id, ...d.data() })));\n    } catch (e) { setBoostOrders([]); }\n    setOrdersLoading(false);\n  }\n\n  const BOOST_COLLECTION = { post: 'posts', profile: 'users', shop: 'shops', artist: 'artists' };\n\n  async function approveOrder(order) {\n    try {\n      const col = BOOST_COLLECTION[order.targetType] || 'posts';\n      const boostUntil = new Date();\n      boostUntil.setDate(boostUntil.getDate() + (order.days || 1));\n      await updateDoc(doc(db, col, order.targetId), {\n        isBoosted: true, boostDays: order.days || 1,\n        boostUntil: boostUntil.toISOString(), boostedAt: new Date().toISOString(),\n      });\n      await updateDoc(doc(db, 'boostOrders', order.id), { status: 'approved', processedAt: new Date().toISOString() });\n      try {\n        await addDoc(collection(db, 'notifications'), {\n          toUid: order.requesterUid, fromUid: currentUser.uid, fromName: 'Trengo Admin', fromPhoto: '',\n          type: 'boost', message: `Votre commande de boost (${order.days} jour${order.days > 1 ? 's' : ''}) a \u00e9t\u00e9 valid\u00e9e \ud83d\ude80`,\n          read: false, createdAt: serverTimestamp(),\n        });\n      } catch (e) { /* notif optionnelle */ }\n      setBoostOrders(prev => prev.map(o => o.id === order.id ? { ...o, status: 'approved' } : o));\n      showMsg(`\u2705 Commande de ${order.requesterName} valid\u00e9e (${order.days}j)`);\n    } catch (err) {\n      showMsg('\u274c Erreur : ' + (err?.message || err));\n    }\n  }\n\n  async function refuseOrder(order) {\n    try {\n      await updateDoc(doc(db, 'boostOrders', order.id), { status: 'refused', processedAt: new Date().toISOString() });\n      try {\n        await addDoc(collection(db, 'notifications'), {\n          toUid: order.requesterUid, fromUid: currentUser.uid, fromName: 'Trengo Admin', fromPhoto: '',\n          type: 'general', message: `Votre commande de boost a \u00e9t\u00e9 refus\u00e9e.`,\n          read: false, createdAt: serverTimestamp(),\n        });\n      } catch (e) { /* notif optionnelle */ }\n      setBoostOrders(prev => prev.map(o => o.id === order.id ? { ...o, status: 'refused' } : o));\n      showMsg(`\u26d4 Commande de ${order.requesterName} refus\u00e9e`);\n    } catch (err) {\n      showMsg('\u274c Erreur : ' + (err?.message || err));\n    }\n  }\n\n  // \u2500\u2500 Actions Utilisateurs \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n  async function toggleVip(user) {\n    const v = !user.isVip;\n    await updateDoc(doc(db, 'users', user.id), { isVip: v });\n    setUsers(prev => prev.map(u => u.id === user.id ? { ...u, isVip: v } : u));\n    showMsg(`${user.fullName} \u2192 VIP ${v ? 'activ\u00e9 \u2705' : 'retir\u00e9 \u274c'}`);\n  }\n  async function toggleBan(user) {\n    const v = !user.isBanned;\n    try {\n      await updateDoc(doc(db, 'users', user.id), { isBanned: v });\n      setUsers(prev => prev.map(u => u.id === user.id ? { ...u, isBanned: v } : u));\n      showMsg(`${user.fullName} \u2192 ${v ? '\ud83d\udeab Bloqu\u00e9' : '\u2705 D\u00e9bloqu\u00e9'}`);\n    } catch { showMsg('\u274c Erreur (v\u00e9rifiez les r\u00e8gles Firestore)'); }\n  }\n  async function toggleDisable(user) {\n    const v = !user.disabled;\n    try {\n      await updateDoc(doc(db, 'users', user.id), { disabled: v });\n      setUsers(prev => prev.map(u => u.id === user.id ? { ...u, disabled: v } : u));\n      showMsg(`${user.fullName} \u2192 ${v ? '\ud83d\udca4 D\u00e9sactiv\u00e9' : '\u2705 R\u00e9activ\u00e9'}`);\n    } catch { showMsg('\u274c Erreur (v\u00e9rifiez les r\u00e8gles Firestore)'); }\n  }\n  function copyId(id) {\n    try { navigator.clipboard.writeText(id); showMsg('ID copi\u00e9 : ' + id); }\n    catch { showMsg(id); }\n  }\n\n  // \u2500\u2500 Boost \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n  async function activateBoost(post) {\n    const days = parseInt(boostDays[post.id]);\n    if (!days || days < 1 || days > 365) { showMsg('\u274c Nombre de jours invalide (1\u2013365)'); return; }\n    setBoostLoading(p => ({ ...p, [post.id]: true }));\n    try {\n      const boostUntil = new Date();\n      boostUntil.setDate(boostUntil.getDate() + days);\n      await updateDoc(doc(db, 'posts', post.id), {\n        isBoosted: true, boostDays: days,\n        boostUntil: boostUntil.toISOString(), boostedAt: new Date().toISOString(),\n      });\n      try {\n        await addDoc(collection(db, 'notifications'), {\n          toUid: post.uid, fromUid: currentUser.uid, fromName: 'Trengo Admin', fromPhoto: '',\n          type: 'boost', postId: post.id,\n          message: `Votre publication a \u00e9t\u00e9 boost\u00e9e pendant ${days} jour${days > 1 ? 's' : ''} \ud83d\ude80`,\n          read: false, createdAt: serverTimestamp(),\n        });\n      } catch (e) { /* notif optionnelle */ }\n      setPosts(prev => prev.map(p => p.id === post.id\n        ? { ...p, isBoosted: true, boostDays: days, boostUntil: boostUntil.toISOString() } : p));\n      showMsg(`\ud83d\ude80 Post de @${post.authorUsername || post.authorName} boost\u00e9 ${days}j !`);\n      setBoostDays(p => ({ ...p, [post.id]: '' }));\n    } catch (err) {\n      showMsg('\u274c Boost refus\u00e9 \u2014 mettez \u00e0 jour les r\u00e8gles Firestore (isAdmin)');\n    }\n    setBoostLoading(p => ({ ...p, [post.id]: false }));\n  }\n  async function deactivateBoost(post) {\n    setBoostLoading(p => ({ ...p, [post.id]: true }));\n    try {\n      await updateDoc(doc(db, 'posts', post.id), { isBoosted: false, boostDays: 0, boostUntil: null });\n      setPosts(prev => prev.map(p => p.id === post.id ? { ...p, isBoosted: false, boostDays: 0, boostUntil: null } : p));\n      showMsg(`\u26d4 Boost retir\u00e9 du post de @${post.authorUsername || post.authorName}`);\n    } catch { showMsg('\u274c Erreur (r\u00e8gles Firestore)'); }\n    setBoostLoading(p => ({ ...p, [post.id]: false }));\n  }\n  function boostTimeLeft(post) {\n    if (!post.boostUntil) return null;\n    const diff = new Date(post.boostUntil) - new Date();\n    if (diff <= 0) return 'Expir\u00e9';\n    const d = Math.floor(diff / 86400000), h = Math.floor((diff % 86400000) / 3600000);\n    return d > 0 ? `${d}j ${h}h restants` : `${h}h restants`;\n  }\n\n  // \u2500\u2500 Actions Boutiques / Artistes \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n  async function verifyBiz(kind, item) {\n    const col = kind === 'shop' ? 'shops' : 'artists';\n    const setter = kind === 'shop' ? setShops : setArtists;\n    const v = !item.verified;\n    try {\n      await updateDoc(doc(db, col, item.id), { verified: v });\n      setter(prev => prev.map(x => x.id === item.id ? { ...x, verified: v } : x));\n      showMsg(`${item.name} \u2192 ${v ? '\u2705 V\u00e9rifi\u00e9' : 'V\u00e9rif. retir\u00e9e'}`);\n    } catch { showMsg('\u274c Erreur (r\u00e8gles Firestore)'); }\n  }\n  async function deleteBiz(kind, item) {\n    const label = kind === 'shop' ? 'boutique' : 'canal artiste';\n    if (!window.confirm(`Supprimer d\u00e9finitivement ${label} \"${item.name}\" ?`)) return;\n    const col = kind === 'shop' ? 'shops' : 'artists';\n    const setter = kind === 'shop' ? setShops : setArtists;\n    try {\n      await deleteDoc(doc(db, col, item.id));\n      setter(prev => prev.filter(x => x.id !== item.id));\n      showMsg(`\ud83d\uddd1\ufe0f ${item.name} supprim\u00e9`);\n    } catch { showMsg('\u274c Erreur (r\u00e8gles Firestore)'); }\n  }\n\n  function showMsg(txt) { setMessage(txt); setTimeout(() => setMessage(''), 4000); }\n\n  // \u2500\u2500 Filtres \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n  const filteredUsers = users.filter(u =>\n    u.fullName?.toLowerCase().includes(search.toLowerCase()) ||\n    u.username?.toLowerCase().includes(search.toLowerCase()) ||\n    u.email?.toLowerCase().includes(search.toLowerCase()) ||\n    u.id?.toLowerCase().includes(search.toLowerCase())\n  );\n  const filteredPosts = posts.filter(p =>\n    p.authorName?.toLowerCase().includes(boostSearch.toLowerCase()) ||\n    p.authorUsername?.toLowerCase().includes(boostSearch.toLowerCase()) ||\n    p.content?.toLowerCase().includes(boostSearch.toLowerCase())\n  );\n  const blow = bizSearch.toLowerCase();\n  const filteredShops = shops.filter(s => (s.name || '').toLowerCase().includes(blow));\n  const filteredArtists = artists.filter(a => (a.name || '').toLowerCase().includes(blow));\n\n  const nBanned = users.filter(u => u.isBanned).length;\n  const nDisabled = users.filter(u => u.disabled).length;\n\n  // \u2500\u2500 \u00c9tats bloquants \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n  if (isAdmin === null) {\n    return (\n      <div style={{ minHeight: '100vh', background: '#F0F2F5', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>\n        <p style={{ color: '#65676B', fontFamily: 'Poppins' }}>V\u00e9rification des droits...</p>\n      </div>\n    );\n  }\n  if (isAdmin === false) {\n    return (\n      <div style={{ minHeight: '100vh', background: '#F0F2F5', display: 'flex', alignItems: 'center', justifyContent: 'center', padding: 20 }}>\n        <div style={{ background: '#FFFFFF', borderRadius: 20, padding: 32, maxWidth: 340, textAlign: 'center', border: '1px solid #E4E6EB', fontFamily: 'Poppins' }}>\n          <div style={{ fontSize: 48, marginBottom: 12 }}>\ud83d\udd12</div>\n          <h2 style={{ color: '#050505', fontWeight: 800, fontSize: 20, marginBottom: 8 }}>Acc\u00e8s refus\u00e9</h2>\n          <p style={{ color: '#65676B', fontSize: 14, marginBottom: 24 }}>Vous n'avez pas les droits administrateur.</p>\n          <button onClick={() => navigate('/')} style={{ background: 'linear-gradient(135deg,#FF2D8D,#FF7AB8)', color: 'white', border: 'none', borderRadius: 25, padding: '12px 28px', fontWeight: 700, fontSize: 14, cursor: 'pointer', fontFamily: 'Poppins' }}>\n            Retour \u00e0 l'accueil\n          </button>\n        </div>\n      </div>\n    );\n  }\n\n  const NAV_ITEMS = [\n    { key: 'users',   label: 'Utilisateurs', icon: '\ud83d\udc65' },\n    { key: 'boost',   label: 'Boost (manuel)', icon: '\ud83d\ude80' },\n    { key: 'shops',   label: 'Boutiques', icon: '\ud83d\udecd\ufe0f' },\n    { key: 'artists', label: 'Artistes', icon: '\ud83c\udfb5' },\n    { key: 'orders',  label: 'Commandes Boost', icon: '\ud83d\udce2', badge: boostOrders.filter(o=>o.status==='pending').length },\n    { key: 'reports', label: 'Signalements', icon: '\ud83d\udea9', badge: reports.filter(r=>r.status==='pending'||!r.status).length },\n  ];\n\n  const tabBtn = (key, label) => (\n    <button key={key} onClick={() => setActiveTab(key)}\n      style={{\n        flex: 1, padding: '10px 6px', borderRadius: 14, border: activeTab === key ? 'none' : '1px solid #E4E6EB',\n        cursor: 'pointer', fontFamily: 'Poppins', fontWeight: 600, fontSize: 12.5, whiteSpace: 'nowrap',\n        background: activeTab === key ? 'linear-gradient(135deg,#FF2D8D,#FF7AB8)' : '#FFFFFF',\n        color: activeTab === key ? 'white' : '#65676B',\n      }}>{label}</button>\n  );\n\n  const pill = (txt, bg, color, border) => (\n    <span style={{ background: bg, color, fontSize: 9, fontWeight: 700, padding: '1px 6px', borderRadius: 6, border: border || 'none' }}>{txt}</span>\n  );\n\n  return (\n    <div style={{ minHeight: '100vh', background: '#F0F2F5', padding: '20px 16px', fontFamily: 'Poppins, sans-serif', color: '#050505' }}>\n      <div style={{ maxWidth: 700, margin: '0 auto' }}>\n\n        {/* Header */}\n        <div style={{ display: 'flex', alignItems: 'center', gap: 12, marginBottom: 16 }}>\n          <div style={{ width: 44, height: 44, borderRadius: '50%', background: 'linear-gradient(135deg,#FF2D8D,#FF7AB8)', display: 'flex', alignItems: 'center', justifyContent: 'center', flexShrink: 0 }}>\n            <HiShieldCheck size={24} color=\"white\" />\n          </div>\n          <div>\n            <h2 style={{ fontWeight: 800, fontSize: 20, color: '#050505' }}>Panel Admin</h2>\n            <p style={{ fontSize: 12, color: '#65676B' }}>Connect\u00e9 : {userProfile?.fullName}</p>\n          </div>\n          <div style={{ marginLeft: 'auto', display: 'flex', gap: 8 }}>\n            <button onClick={() => setNavMenuOpen(true)} style={{ width: 36, height: 36, borderRadius: '50%', background: '#E4E6EB', border: 'none', cursor: 'pointer', color: '#050505', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>\n              <HiMenu size={18} />\n            </button>\n            <button onClick={() => navigate('/')} style={{ background: '#E4E6EB', border: 'none', borderRadius: 20, padding: '6px 14px', color: '#65676B', cursor: 'pointer', fontSize: 13 }}>\n              \u2190 Retour\n            </button>\n          </div>\n        </div>\n\n        {/* Installation PWA */}\n        <div style={{ background: 'linear-gradient(135deg,#1877F218,#00C85311)', border: '1px solid #1877F244', borderRadius: 14, padding: '12px 14px', marginBottom: 14, display: 'flex', alignItems: 'center', gap: 12 }}>\n          <HiDownload size={22} color=\"#3b82f6\" style={{ flexShrink: 0 }} />\n          <div style={{ flex: 1, minWidth: 0 }}>\n            <p style={{ fontWeight: 700, fontSize: 14, color: '#050505' }}>Installer l'application Trengo</p>\n            <p style={{ fontSize: 11, color: '#65676B' }}>\n              {installState === 'installed' ? '\u2705 D\u00e9j\u00e0 install\u00e9e sur cet appareil'\n                : installState === 'ready' ? \"Pr\u00eate \u00e0 installer sur l'\u00e9cran d'accueil\"\n                : 'Ouvrez dans Chrome (hors mode install\u00e9) pour activer'}\n            </p>\n          </div>\n          <button onClick={doInstall} disabled={installState !== 'ready'}\n            style={{\n              flexShrink: 0, border: 'none', borderRadius: 20, padding: '9px 16px', fontWeight: 700, fontSize: 13, fontFamily: 'Poppins',\n              cursor: installState === 'ready' ? 'pointer' : 'not-allowed',\n              background: installState === 'ready' ? 'linear-gradient(135deg,#1877F2,#42A5F5)' : '#E4E6EB',\n              color: installState === 'ready' ? '#fff' : '#65676B',\n            }}>\n            {installState === 'installed' ? 'Install\u00e9e' : 'Installer'}\n          </button>\n        </div>\n\n        {/* Diagnostic Push */}\n        <PushDiagnostic uid={currentUser?.uid} />\n\n        {navMenuOpen && (\n          <div onClick={() => setNavMenuOpen(false)} style={{ position: 'fixed', inset: 0, background: 'rgba(0,0,0,.45)', zIndex: 700, display: 'flex', alignItems: 'flex-end', justifyContent: 'center' }}>\n            <div onClick={e => e.stopPropagation()} style={{ background: '#FFFFFF', borderRadius: '20px 20px 0 0', width: '100%', maxWidth: 480, padding: '10px 0 24px', maxHeight: '75vh', overflowY: 'auto' }}>\n              <div style={{ width: 40, height: 4, background: '#E4E6EB', borderRadius: 2, margin: '6px auto 14px' }} />\n              <p style={{ fontWeight: 800, fontSize: 15, color: '#050505', padding: '0 20px 10px' }}>Menu Admin</p>\n              {NAV_ITEMS.map(item => (\n                <button key={item.key} onClick={() => { setActiveTab(item.key); setNavMenuOpen(false); }}\n                  style={{ width: '100%', display: 'flex', alignItems: 'center', gap: 14, padding: '14px 20px', background: activeTab === item.key ? '#FFF0F7' : 'none', border: 'none', cursor: 'pointer', textAlign: 'left' }}>\n                  <span style={{ fontSize: 20 }}>{item.icon}</span>\n                  <span style={{ flex: 1, fontWeight: activeTab === item.key ? 700 : 500, fontSize: 15, color: activeTab === item.key ? '#FF2D8D' : '#050505' }}>{item.label}</span>\n                  {item.badge > 0 && <span style={{ background: '#FF2D8D', color: 'white', fontSize: 11, fontWeight: 700, borderRadius: 10, padding: '2px 8px' }}>{item.badge}</span>}\n                </button>\n              ))}\n              <div style={{ borderTop: '1px solid #F0F2F5', marginTop: 6, paddingTop: 6 }}>\n                <button onClick={() => { setNavMenuOpen(false); navigate('/'); }}\n                  style={{ width: '100%', display: 'flex', alignItems: 'center', gap: 14, padding: '14px 20px', background: 'none', border: 'none', cursor: 'pointer', textAlign: 'left', color: '#65676B', fontSize: 15 }}>\n                  \u2190 Retour \u00e0 l'accueil\n                </button>\n              </div>\n            </div>\n          </div>\n        )}\n\n        {/* Flash message */}\n        {message && (\n          <div style={{ background: message.startsWith('\u274c') ? '#3b0000' : '#14532d', border: `1px solid ${message.startsWith('\u274c') ? '#ef4444' : '#16a34a'}`, borderRadius: 12, padding: '10px 16px', marginBottom: 14, fontSize: 14, color: message.startsWith('\u274c') ? '#fca5a5' : '#86efac', wordBreak: 'break-all' }}>\n            {message}\n          </div>\n        )}\n\n        {/* Stats */}\n        <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr 1fr 1fr', gap: 8, marginBottom: 18 }}>\n          {[\n            { label: 'Utilisateurs', value: users.length, color: '#3b82f6' },\n            { label: 'VIP', value: users.filter(u => u.isVip).length, color: '#1877F2' },\n            { label: 'Bloqu\u00e9s', value: nBanned, color: '#ef4444' },\n            { label: 'D\u00e9sactiv\u00e9s', value: nDisabled, color: '#f59e0b' },\n            { label: 'Publications', value: posts.length, color: '#22c55e' },\n            { label: 'Boost\u00e9s', value: posts.filter(p => p.isBoosted).length, color: '#a855f7' },\n            { label: 'Boutiques', value: shops.length, color: '#06b6d4' },\n            { label: 'Artistes', value: artists.length, color: '#ec4899' },\n          ].map(s => (\n            <div key={s.label} style={{ background: '#FFFFFF', borderRadius: 14, padding: '12px 6px', textAlign: 'center', border: '1px solid #E4E6EB', boxShadow: '0 1px 3px rgba(0,0,0,.06)' }}>\n              <p style={{ fontWeight: 800, fontSize: 19, color: s.color }}>{s.value}</p>\n              <p style={{ fontSize: 9.5, color: '#65676B' }}>{s.label}</p>\n            </div>\n          ))}\n        </div>\n\n        {/* Section active + acc\u00e8s au menu */}\n        <button onClick={() => setNavMenuOpen(true)} style={{ width: '100%', display: 'flex', alignItems: 'center', justifyContent: 'space-between', background: '#FFFFFF', border: '1px solid #E4E6EB', borderRadius: 14, padding: '12px 16px', marginBottom: 18, cursor: 'pointer', boxShadow: '0 1px 3px rgba(0,0,0,.06)' }}>\n          <span style={{ display: 'flex', alignItems: 'center', gap: 8, fontWeight: 700, fontSize: 15, color: '#050505' }}>\n            {NAV_ITEMS.find(n => n.key === activeTab)?.icon} {NAV_ITEMS.find(n => n.key === activeTab)?.label}\n          </span>\n          <span style={{ display: 'flex', alignItems: 'center', gap: 6 }}>\n            {boostOrders.filter(o=>o.status==='pending').length > 0 && activeTab !== 'orders' && (\n              <span style={{ background: '#FF2D8D', color: 'white', fontSize: 10, fontWeight: 700, borderRadius: 10, padding: '2px 7px' }}>{boostOrders.filter(o=>o.status==='pending').length}</span>\n            )}\n            {reports.filter(r=>r.status==='pending'||!r.status).length > 0 && activeTab !== 'reports' && (\n              <span style={{ background: '#F2B300', color: 'white', fontSize: 10, fontWeight: 700, borderRadius: 10, padding: '2px 7px' }}>{reports.filter(r=>r.status==='pending'||!r.status).length}</span>\n            )}\n            <HiChevronDown size={18} color=\"#65676B\" />\n          </span>\n        </button>\n\n        {/* \u2500\u2500 TAB USERS \u2500\u2500 */}\n        {activeTab === 'users' && (\n          <>\n            <div style={{ position: 'relative', marginBottom: 14 }}>\n              <HiSearch style={{ position: 'absolute', left: 12, top: '50%', transform: 'translateY(-50%)', color: '#65676B' }} size={17} />\n              <input placeholder=\"Rechercher (nom, @, email, ID)...\" value={search} onChange={e => setSearch(e.target.value)}\n                style={{ width: '100%', background: '#FFFFFF', border: '1px solid #E4E6EB', borderRadius: 12, padding: '10px 10px 10px 36px', color: '#050505', fontFamily: 'Poppins', fontSize: 14, boxSizing: 'border-box' }} />\n            </div>\n            {loading ? <SkeletonList rows={5} /> : (\n              <div style={{ display: 'flex', flexDirection: 'column', gap: 8 }}>\n                {filteredUsers.map(user => (\n                  <div key={user.id} style={{ background: '#FFFFFF', borderRadius: 14, padding: '12px 14px', border: user.isBanned ? '1px solid #ef4444' : user.disabled ? '1px solid #f59e0b' : user.isVip ? '1px solid #1877F2' : '1px solid #E4E6EB' }}>\n                    <div style={{ display: 'flex', alignItems: 'center', gap: 12 }}>\n                      <img src={user.photoURL || `https://ui-avatars.com/api/?name=${encodeURIComponent(user.fullName || 'U')}&background=1877F2&color=fff`} alt=\"\" style={{ width: 44, height: 44, borderRadius: '50%', objectFit: 'cover', flexShrink: 0, opacity: user.disabled ? 0.5 : 1 }} />\n                      <div style={{ flex: 1, minWidth: 0 }}>\n                        <div style={{ display: 'flex', alignItems: 'center', gap: 5, flexWrap: 'wrap' }}>\n                          <p style={{ fontWeight: 600, fontSize: 14, color: '#050505' }}>{user.fullName}</p>\n                          {user.isVip && <img src='/vip-badge.png' style={{ width: 22, height: 22, flexShrink: 0, objectFit: 'contain' }} alt='VIP' />}\n                          {user.isAdmin && pill('ADMIN', '#1d4ed8', 'white')}\n                          {user.isBanned && pill('BLOQU\u00c9', '#7f1d1d', '#fca5a5')}\n                          {user.disabled && pill('D\u00c9SACTIV\u00c9', '#78350f', '#fcd34d')}\n                        </div>\n                        <p style={{ fontSize: 12, color: '#65676B' }}>@{user.username} \u00b7 {user.email}</p>\n                        <p onClick={() => copyId(user.id)} style={{ fontSize: 10.5, color: '#4b5563', display: 'flex', alignItems: 'center', gap: 4, cursor: 'pointer', marginTop: 2 }}>\n                          <HiDuplicate size={11} /> ID : {user.id}\n                        </p>\n                      </div>\n                    </div>\n                    {/* Actions */}\n                    <div style={{ display: 'flex', gap: 6, marginTop: 10, flexWrap: 'wrap' }}>\n                      <button onClick={() => toggleVip(user)} style={{ flex: 1, minWidth: 90, background: user.isVip ? '#E4E6EB' : 'linear-gradient(135deg,#FF2D8D,#FF7AB8)', border: 'none', borderRadius: 18, padding: '7px 10px', color: user.isVip ? '#1877F2' : 'white', cursor: 'pointer', fontSize: 12, fontWeight: 700, display: 'flex', alignItems: 'center', justifyContent: 'center', gap: 4, fontFamily: 'Poppins' }}>\n                        <HiStar size={13} /> {user.isVip ? 'Retirer VIP' : 'VIP'}\n                      </button>\n                      <button onClick={() => toggleBan(user)} style={{ flex: 1, minWidth: 90, background: user.isBanned ? '#E4E6EB' : '#3b0000', border: '1px solid #ef4444', borderRadius: 18, padding: '7px 10px', color: '#fca5a5', cursor: 'pointer', fontSize: 12, fontWeight: 700, display: 'flex', alignItems: 'center', justifyContent: 'center', gap: 4, fontFamily: 'Poppins' }}>\n                        <HiBan size={13} /> {user.isBanned ? 'D\u00e9bloquer' : 'Bloquer'}\n                      </button>\n                      <button onClick={() => toggleDisable(user)} style={{ flex: 1, minWidth: 90, background: user.disabled ? '#E4E6EB' : '#3a2a00', border: '1px solid #f59e0b', borderRadius: 18, padding: '7px 10px', color: '#fcd34d', cursor: 'pointer', fontSize: 12, fontWeight: 700, display: 'flex', alignItems: 'center', justifyContent: 'center', gap: 4, fontFamily: 'Poppins' }}>\n                        <HiClock size={13} /> {user.disabled ? 'R\u00e9activer' : 'D\u00e9sactiver'}\n                      </button>\n                    </div>\n                  </div>\n                ))}\n              </div>\n            )}\n          </>\n        )}\n\n        {/* \u2500\u2500 TAB BOOST \u2500\u2500 */}\n        {activeTab === 'boost' && (\n          <>\n            <div style={{ background: 'linear-gradient(135deg,#7c3aed22,#1877F211)', border: '1px solid #7c3aed44', borderRadius: 14, padding: '14px 16px', marginBottom: 16, display: 'flex', gap: 12, alignItems: 'flex-start' }}>\n              <HiLightningBolt size={22} color=\"#a855f7\" style={{ flexShrink: 0, marginTop: 1 }} />\n              <div>\n                <p style={{ fontWeight: 700, fontSize: 14, color: '#d8b4fe', marginBottom: 4 }}>Boost de publication</p>\n                <p style={{ fontSize: 12, color: '#65676B', lineHeight: 1.7 }}>\n                  Saisissez le nombre de jours. Le post remonte en t\u00eate du fil avec le badge <strong style={{ color: '#a855f7' }}>Sponsoris\u00e9</strong>. \u26a0\ufe0f N\u00e9cessite les r\u00e8gles Firestore <strong style={{ color: '#050505' }}>isAdmin</strong> \u00e0 jour.\n                </p>\n              </div>\n            </div>\n            <div style={{ position: 'relative', marginBottom: 14 }}>\n              <HiSearch style={{ position: 'absolute', left: 12, top: '50%', transform: 'translateY(-50%)', color: '#65676B' }} size={17} />\n              <input placeholder=\"Rechercher une publication...\" value={boostSearch} onChange={e => setBoostSearch(e.target.value)}\n                style={{ width: '100%', background: '#FFFFFF', border: '1px solid #E4E6EB', borderRadius: 12, padding: '10px 10px 10px 36px', color: '#050505', fontFamily: 'Poppins', fontSize: 14, boxSizing: 'border-box' }} />\n            </div>\n            <div style={{ display: 'flex', flexDirection: 'column', gap: 10 }}>\n              {filteredPosts.map(post => {\n                const timeLeft = boostTimeLeft(post);\n                const isExpanded = expandedPost === post.id;\n                return (\n                  <div key={post.id} style={{ background: '#FFFFFF', borderRadius: 16, border: post.isBoosted ? '1px solid #a855f7' : '1px solid #E4E6EB', overflow: 'hidden' }}>\n                    <div style={{ padding: '12px 14px', display: 'flex', alignItems: 'center', gap: 10, cursor: 'pointer' }} onClick={() => setExpandedPost(isExpanded ? null : post.id)}>\n                      <img src={post.authorPhoto || `https://ui-avatars.com/api/?name=${encodeURIComponent(post.authorName || 'U')}&background=1877F2&color=fff`} alt=\"\" style={{ width: 40, height: 40, borderRadius: '50%', objectFit: 'cover', flexShrink: 0 }} />\n                      <div style={{ flex: 1, minWidth: 0 }}>\n                        <div style={{ display: 'flex', alignItems: 'center', gap: 6 }}>\n                          <p style={{ fontWeight: 600, fontSize: 13, color: '#050505' }}>{post.authorName}</p>\n                          {post.isBoosted && <span style={{ background: 'linear-gradient(135deg,#7c3aed,#a855f7)', color: 'white', fontSize: 9, fontWeight: 700, padding: '1px 6px', borderRadius: 6, display: 'flex', alignItems: 'center', gap: 2 }}><HiLightningBolt size={9} /> Boost\u00e9</span>}\n                        </div>\n                        <p style={{ fontSize: 11, color: '#65676B', overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap', maxWidth: 200 }}>{post.content || (post.mediaURL ? '\ud83d\udcce Media' : '\u2014')}</p>\n                        {post.isBoosted && timeLeft && <p style={{ fontSize: 10, color: '#a855f7', display: 'flex', alignItems: 'center', gap: 3, marginTop: 2 }}><HiClock size={10} /> {timeLeft} \u00b7 {post.boostDays}j total</p>}\n                      </div>\n                      <span style={{ color: '#65676B', flexShrink: 0 }}>{isExpanded ? <HiChevronUp size={18} /> : <HiChevronDown size={18} />}</span>\n                    </div>\n                    {isExpanded && (\n                      <div style={{ borderTop: '1px solid #E4E6EB', padding: '14px' }}>\n                        {post.content && <p style={{ fontSize: 13, color: '#050505', marginBottom: 10, lineHeight: 1.5, background: '#F0F2F5', borderRadius: 10, padding: '10px 12px' }}>{post.content.slice(0, 150)}{post.content.length > 150 ? '...' : ''}</p>}\n                        {post.mediaURL && post.mediaType === 'image' && <img src={post.mediaURL} alt=\"\" style={{ width: '100%', maxHeight: 160, objectFit: 'cover', borderRadius: 10, marginBottom: 10 }} />}\n                        {post.isBoosted && (\n                          <div style={{ background: '#2e1065', borderRadius: 12, padding: '12px 14px', marginBottom: 12, display: 'flex', alignItems: 'center', justifyContent: 'space-between', flexWrap: 'wrap', gap: 8 }}>\n                            <div>\n                              <p style={{ color: '#d8b4fe', fontWeight: 600, fontSize: 13 }}>\u2705 Boost actif \u2014 {post.boostDays}j</p>\n                              <p style={{ color: '#a855f7', fontSize: 12 }}>{timeLeft}</p>\n                            </div>\n                            <button onClick={() => deactivateBoost(post)} disabled={boostLoading[post.id]} style={{ background: '#E4E6EB', border: '1px solid #1877F2', borderRadius: 20, padding: '6px 14px', color: '#1877F2', cursor: 'pointer', fontSize: 12, fontWeight: 600, fontFamily: 'Poppins', display: 'flex', alignItems: 'center', gap: 4 }}><HiX size={13} /> Retirer boost</button>\n                          </div>\n                        )}\n                        <div style={{ display: 'flex', gap: 8, alignItems: 'center' }}>\n                          <div style={{ position: 'relative', flex: 1 }}>\n                            <HiClock style={{ position: 'absolute', left: 12, top: '50%', transform: 'translateY(-50%)', color: '#65676B' }} size={16} />\n                            <input type=\"number\" min=\"1\" max=\"365\" placeholder=\"Nb. jours (ex: 7)\" value={boostDays[post.id] || ''} onChange={e => setBoostDays(p => ({ ...p, [post.id]: e.target.value }))}\n                              style={{ width: '100%', background: '#F0F2F5', border: '1px solid #E4E6EB', borderRadius: 12, padding: '10px 14px 10px 40px', color: '#050505', fontFamily: 'Poppins', fontSize: 14, boxSizing: 'border-box' }} />\n                          </div>\n                          <span style={{ color: '#65676B', fontSize: 13, fontWeight: 600 }}>j</span>\n                          <button onClick={() => activateBoost(post)} disabled={boostLoading[post.id] || !boostDays[post.id]}\n                            style={{ background: (!boostDays[post.id] || boostLoading[post.id]) ? '#E4E6EB' : 'linear-gradient(135deg,#7c3aed,#a855f7)', border: 'none', borderRadius: 20, padding: '10px 18px', color: 'white', cursor: boostDays[post.id] ? 'pointer' : 'not-allowed', fontSize: 13, fontWeight: 700, fontFamily: 'Poppins', display: 'flex', alignItems: 'center', gap: 5, flexShrink: 0, opacity: boostLoading[post.id] ? 0.6 : 1 }}>\n                            <HiLightningBolt size={14} /> {boostLoading[post.id] ? '...' : post.isBoosted ? 'Prolonger' : 'Booster'}\n                          </button>\n                        </div>\n                      </div>\n                    )}\n                  </div>\n                );\n              })}\n            </div>\n          </>\n        )}\n\n        {/* \u2500\u2500 TAB SHOPS / ARTISTS \u2500\u2500 */}\n        {activeTab === 'reports' && (\n          <div>\n            {reports.length === 0 ? (\n              <p style={{ textAlign:'center', color:'#65676B', padding:30, fontSize:13 }}>Aucun signalement</p>\n            ) : reports.map(r => (\n              <div key={r.id} style={{ background:'#FFFFFF', borderRadius:14, padding:'12px 14px', marginBottom:10, border: (r.status==='pending'||!r.status) ? '1px solid #F2B300' : '1px solid #E4E6EB', boxShadow:'0 1px 3px rgba(0,0,0,.06)' }}>\n                <div style={{ display:'flex', alignItems:'center', justifyContent:'space-between', gap:8 }}>\n                  <span style={{ fontSize:11, fontWeight:700, color:'#65676B', textTransform:'uppercase' }}>\n                    {r.type === 'post' ? '\ud83d\udcdd Publication' : r.type === 'shop' ? '\ud83d\udecd\ufe0f Boutique' : r.type === 'artist' ? '\ud83c\udfb5 Artiste' : '\ud83d\udc64 Compte'}\n                  </span>\n                  {(r.status==='pending'||!r.status)\n                    ? <span style={{ fontSize:10, fontWeight:700, color:'#F2B300' }}>EN ATTENTE</span>\n                    : <span style={{ fontSize:10, fontWeight:700, color: r.status==='resolved' ? '#22c55e' : '#65676B' }}>{r.status==='resolved' ? 'TRAIT\u00c9' : 'IGNOR\u00c9'}</span>}\n                </div>\n                <p style={{ fontWeight:800, fontSize:14, marginTop:6, color:'#050505' }}>{r.motif || 'Motif non pr\u00e9cis\u00e9'}</p>\n                {r.detail && <p style={{ fontSize:12.5, color:'#65676B', marginTop:2 }}>{r.detail}</p>}\n                <p style={{ fontSize:12, color:'#65676B', marginTop:6 }}>\n                  Cible : <b>{r.targetAuthor || r.targetId}</b> \u00b7 Signal\u00e9 par <b>{r.reportedByName || r.reportedBy}</b>\n                </p>\n                {(r.status==='pending'||!r.status) && (\n                  <div style={{ display:'flex', gap:8, marginTop:10 }}>\n                    <button onClick={() => resolveReport(r)} style={{ flex:1, background:'linear-gradient(135deg,#FF2D8D,#FF7AB8)', border:'none', borderRadius:16, padding:'9px 0', color:'white', fontWeight:700, fontSize:13, cursor:'pointer', fontFamily:'Poppins' }}>\u2705 Trait\u00e9</button>\n                    <button onClick={() => dismissReport(r)} style={{ flex:1, background:'#F0F2F5', border:'none', borderRadius:16, padding:'9px 0', color:'#65676B', fontWeight:700, fontSize:13, cursor:'pointer', fontFamily:'Poppins' }}>Ignorer</button>\n                  </div>\n                )}\n              </div>\n            ))}\n          </div>\n        )}\n\n        {activeTab === 'orders' && (\n          <div>\n            {ordersLoading ? (\n              <SkeletonList rows={3} />\n            ) : boostOrders.length === 0 ? (\n              <p style={{ textAlign:'center', color:'#65676B', padding:30, fontSize:13 }}>Aucune commande de boost</p>\n            ) : boostOrders.map(order => (\n              <div key={order.id} style={{ background:'#FFFFFF', borderRadius:14, padding:'12px 14px', marginBottom:10, border: order.status==='pending' ? '1px solid #a855f7' : '1px solid #E4E6EB' }}>\n                <div style={{ display:'flex', alignItems:'center', gap:10 }}>\n                  <img src={order.requesterPhoto || `https://ui-avatars.com/api/?name=${encodeURIComponent(order.requesterName||'U')}&background=1877F2&color=fff`} alt=\"\" style={{ width:38, height:38, borderRadius:'50%', objectFit:'cover', flexShrink:0 }}/>\n                  <div style={{ flex:1, minWidth:0 }}>\n                    <p style={{ fontWeight:700, fontSize:13, color:'#050505' }}>{order.requesterName}</p>\n                    <p style={{ fontSize:11, color:'#65676B' }}>\n                      {order.targetType==='post' ? '\ud83d\udcdd Publication' : order.targetType==='profile' ? '\ud83d\udc64 Profil' : order.targetType==='shop' ? '\ud83d\udecd\ufe0f Boutique' : '\ud83c\udfb5 Artiste'}\n                      {order.targetTitle ? ` \u00b7 ${order.targetTitle}` : ''}\n                    </p>\n                  </div>\n                  {order.targetThumb && <img src={order.targetThumb} alt=\"\" style={{ width:38, height:38, borderRadius:8, objectFit:'cover', flexShrink:0 }}/>}\n                </div>\n                <div style={{ display:'flex', gap:14, marginTop:10, fontSize:12, color:'#B0B3B8', flexWrap:'wrap' }}>\n                  <span>\u23f1\ufe0f {order.days} jour{order.days>1?'s':''}</span>\n                  <span>\ud83d\udcb0 {(order.price||0).toLocaleString()} Ar</span>\n                  <span>\ud83c\udfaf {order.objective==='messages'?'Messages':order.objective==='followers'?'Abonn\u00e9s':'Vues'}</span>\n                  {order.zone?.label && <span>\ud83d\udccd {order.zone.label}</span>}\n                  {!order.zone?.label && order.zone?.radiusKm && <span>\ud83d\udccd rayon {order.zone.radiusKm} km</span>}\n                </div>\n                <div style={{ marginTop:10 }}>\n                  {order.status === 'pending' ? (\n                    <div style={{ display:'flex', gap:8 }}>\n                      <button onClick={() => approveOrder(order)} style={{ flex:1, background:'linear-gradient(135deg,#1877F2,#42A5F5)', border:'none', borderRadius:16, padding:'9px 0', color:'white', fontWeight:700, fontSize:13, cursor:'pointer', fontFamily:'Poppins' }}>\u2705 Valider</button>\n                      <button onClick={() => refuseOrder(order)} style={{ flex:1, background:'#3b0000', border:'1px solid #ef4444', borderRadius:16, padding:'9px 0', color:'#fca5a5', fontWeight:700, fontSize:13, cursor:'pointer', fontFamily:'Poppins' }}>\u274c Refuser</button>\n                    </div>\n                  ) : (\n                    <span style={{ fontSize:12, fontWeight:700, color: order.status==='approved' ? '#22c55e' : '#ef4444' }}>\n                      {order.status==='approved' ? '\u2705 Valid\u00e9e' : '\u274c Refus\u00e9e'}\n                    </span>\n                  )}\n                </div>\n              </div>\n            ))}\n          </div>\n        )}\n\n        {(activeTab === 'shops' || activeTab === 'artists') && (\n          <>\n            <div style={{ position: 'relative', marginBottom: 14 }}>\n              <HiSearch style={{ position: 'absolute', left: 12, top: '50%', transform: 'translateY(-50%)', color: '#65676B' }} size={17} />\n              <input placeholder={activeTab === 'shops' ? 'Rechercher une boutique...' : 'Rechercher un artiste...'} value={bizSearch} onChange={e => setBizSearch(e.target.value)}\n                style={{ width: '100%', background: '#FFFFFF', border: '1px solid #E4E6EB', borderRadius: 12, padding: '10px 10px 10px 36px', color: '#050505', fontFamily: 'Poppins', fontSize: 14, boxSizing: 'border-box' }} />\n            </div>\n            <div style={{ display: 'flex', flexDirection: 'column', gap: 8 }}>\n              {(activeTab === 'shops' ? filteredShops : filteredArtists).map(item => {\n                const kind = activeTab === 'shops' ? 'shop' : 'artist';\n                return (\n                  <div key={item.id} style={{ background: '#FFFFFF', borderRadius: 14, padding: '12px 14px', border: item.verified ? '1px solid #1877F2' : '1px solid #E4E6EB' }}>\n                    <div style={{ display: 'flex', alignItems: 'center', gap: 12 }}>\n                      <div style={{ width: 44, height: 44, borderRadius: 12, background: '#F0F2F5', display: 'flex', alignItems: 'center', justifyContent: 'center', flexShrink: 0, overflow: 'hidden' }}>\n                        {item.photoURL ? <img src={item.photoURL} alt=\"\" style={{ width: '100%', height: '100%', objectFit: 'cover' }} />\n                          : (kind === 'shop' ? <HiShoppingBag size={22} color=\"#06b6d4\" /> : <HiMusicNote size={22} color=\"#ec4899\" />)}\n                      </div>\n                      <div style={{ flex: 1, minWidth: 0 }}>\n                        <div style={{ display: 'flex', alignItems: 'center', gap: 5, flexWrap: 'wrap' }}>\n                          <p style={{ fontWeight: 700, fontSize: 14, color: '#050505' }}>{item.name}</p>\n                          {item.verified && <HiCheckCircle size={15} color=\"#1877F2\" />}\n                          {item.category && pill(item.category, '#F0F2F5', '#65676B', '1px solid #E4E6EB')}\n                        </div>\n                        <p style={{ fontSize: 11, color: '#65676B', display: 'flex', alignItems: 'center', gap: 4 }}>\n                          <HiUserGroup size={11} /> {(item.followers || []).length} abonn\u00e9s\n                        </p>\n                        <p onClick={() => copyId(item.id)} style={{ fontSize: 10.5, color: '#4b5563', cursor: 'pointer', marginTop: 1 }}>ID : {item.id}</p>\n                      </div>\n                    </div>\n                    <div style={{ display: 'flex', gap: 6, marginTop: 10 }}>\n                      <button onClick={() => verifyBiz(kind, item)} style={{ flex: 1, background: item.verified ? '#E4E6EB' : 'linear-gradient(135deg,#1877F2,#42A5F5)', border: 'none', borderRadius: 18, padding: '7px 10px', color: item.verified ? '#1877F2' : 'white', cursor: 'pointer', fontSize: 12, fontWeight: 700, display: 'flex', alignItems: 'center', justifyContent: 'center', gap: 4, fontFamily: 'Poppins' }}>\n                        <HiCheckCircle size={13} /> {item.verified ? 'Retirer v\u00e9rif.' : 'V\u00e9rifier'}\n                      </button>\n                      <button onClick={() => deleteBiz(kind, item)} style={{ flex: 1, background: '#3b0000', border: '1px solid #ef4444', borderRadius: 18, padding: '7px 10px', color: '#fca5a5', cursor: 'pointer', fontSize: 12, fontWeight: 700, display: 'flex', alignItems: 'center', justifyContent: 'center', gap: 4, fontFamily: 'Poppins' }}>\n                        <HiTrash size={13} /> Supprimer\n                      </button>\n                    </div>\n                  </div>\n                );\n              })}\n              {(activeTab === 'shops' ? filteredShops : filteredArtists).length === 0 && (\n                <p style={{ textAlign: 'center', color: '#65676B', padding: 30, fontSize: 13 }}>Aucun r\u00e9sultat</p>\n              )}\n            </div>\n          </>\n        )}\n\n      </div>\n    </div>\n  );\n}\n";

const fs = require('fs');
let OK = 0, SKIP = 0, FAIL = 0;
const ok = (m) => { OK++; console.log('OK ' + m); };
const skip = (m) => { SKIP++; console.log('SKIP ' + m); };
const fail = (m) => { FAIL++; console.log('FAIL ' + m); };

try {
  const p = 'src/components/Skeleton.jsx';
  let s = fs.readFileSync(p, 'utf8');
  if (s.includes('SkeletonList')) skip('Skeleton.jsx : deja a jour');
  else { fs.writeFileSync(p, SKELETON_SRC); ok('Skeleton.jsx : + SkeletonList'); }
} catch (e) { fail('Skeleton.jsx: ' + e.message); }

try {
  const p = 'src/pages/Search.jsx';
  let s = fs.readFileSync(p, 'utf8');
  if (s.includes('SkeletonList')) skip('Search.jsx : skeleton deja actif');
  else { fs.writeFileSync(p, SEARCH_SRC); ok('Search.jsx : skeleton pendant le chargement'); }
} catch (e) { fail('Search.jsx: ' + e.message); }

try {
  const p = 'src/pages/Saved.jsx';
  let s = fs.readFileSync(p, 'utf8');
  if (s.includes('SkeletonList')) skip('Saved.jsx : skeleton deja actif');
  else { fs.writeFileSync(p, SAVED_SRC); ok('Saved.jsx : skeleton pendant le chargement'); }
} catch (e) { fail('Saved.jsx: ' + e.message); }

try {
  const p = 'src/pages/Friends.jsx';
  let s = fs.readFileSync(p, 'utf8');
  if (s.includes('SkeletonList')) skip('Friends.jsx : skeleton deja actif');
  else { fs.writeFileSync(p, FRIENDS_SRC); ok('Friends.jsx : skeleton (suggestions) pendant le chargement'); }
} catch (e) { fail('Friends.jsx: ' + e.message); }

try {
  const p = 'src/pages/AdminPanel.jsx';
  let s = fs.readFileSync(p, 'utf8');
  if (s.includes('SkeletonList')) skip('AdminPanel.jsx : skeleton deja actif');
  else { fs.writeFileSync(p, ADMIN_SRC); ok('AdminPanel.jsx : skeleton (utilisateurs + commandes)'); }
} catch (e) { fail('AdminPanel.jsx: ' + e.message); }

console.log('\nRESUME: OK=' + OK + ' SKIP=' + SKIP + ' FAIL=' + FAIL);
console.log('Necessite patch-skeleton-loading.cjs deja applique (Skeleton.jsx de base).');
